window.BILARA = window.BILARA || {};
window.BILARA["dn23"] = window.BILARA["dn23"] || {};
window.BILARA["dn23"]["vi"] = {
  "dn23:0.1": "Trường Bộ Kinh 23 ",
  "dn23:0.2": "Kinh Pāyāsi ",
  "dn23:1.1": "Tôi nghe như vầy—",
  "dn23:1.2": "Một thời, Tôn giả Kumārakassapa du hành trong xứ Kosala cùng với đại chúng Tỳ-kheo khoảng năm trăm vị, đã đến thành Setabyā của dân Kosala. ",
  "dn23:1.3": "Tại đó, Tôn giả Kumārakassapa trú ở rừng cây siṁsapā, phía bắc Setabyā. ",
  "dn23:1.4": "Lúc bấy giờ, vương tử Pāyāsi cư ngụ tại Setabyā, một nơi phồn thịnh, cỏ cây, gỗ và nước đầy đủ, lúa thóc sung túc, là đất vua ban, tài sản của hoàng gia, do vua Pasenadi nước Kosala cấp làm thái ấp Bà-la-môn. ",
  "dn23:2.0": "1. Chuyện về vương tử Pāyāsi ",
  "dn23:2.1": "Lúc bấy giờ, nơi vương tử Pāyāsi khởi lên ác kiến như sau: ",
  "dn23:2.2": "‘Không có đời sau, không có chúng sinh hóa sinh, không có quả báo dị thục của các nghiệp thiện và ác.’ ",
  "dn23:2.3": "Các Bà-la-môn và gia chủ ở Setabyā nghe rằng: ",
  "dn23:2.4": "‘Này chư vị, sa-môn Kumārakassapa, đệ tử của sa-môn Gotama, đang du hành trong xứ Kosala cùng với đại chúng Tỳ-kheo khoảng năm trăm vị, đã đến Setabyā và đang trú ở rừng cây siṁsapā phía bắc Setabyā. ",
  "dn23:2.5": "Vị Tôn giả Kumārakassapa ấy được tiếng tốt đồn xa như sau: ",
  "dn23:2.6": "“Là bậc hiền trí, thông đạt, thông minh, đa văn, khéo thuyết pháp, biện tài tốt đẹp, trưởng lão và là bậc A-la-hán. ",
  "dn23:2.7": "Thật lành thay được yết kiến những bậc A-la-hán như vậy.”’",
  "dn23:2.8": "Rồi các Bà-la-môn và gia chủ ở Setabyā đi ra khỏi Setabyā, tụ họp thành từng đoàn, cùng nhau đi về hướng bắc đến rừng cây siṁsapā. ",
  "dn23:3.1": "Lúc bấy giờ, vương tử Pāyāsi đang ở trên lầu cao nghỉ trưa. ",
  "dn23:3.2": "Vương tử Pāyāsi thấy các Bà-la-môn và gia chủ ở Setabyā đi ra khỏi Setabyā, tụ họp thành từng đoàn, cùng nhau đi về hướng bắc đến rừng cây siṁsapā, ",
  "dn23:3.3": "thấy vậy liền gọi người hầu cận: ",
  "dn23:3.4": "‘Này khanh, vì sao các Bà-la-môn và gia chủ ở Setabyā đi ra khỏi Setabyā, tụ họp thành từng đoàn, cùng nhau đi về hướng bắc đến rừng cây siṁsapā?’ ",
  "dn23:3.5": "‘Thưa ngài, có sa-môn Kumārakassapa, đệ tử của sa-môn Gotama, đang du hành trong xứ Kosala cùng với đại chúng Tỳ-kheo khoảng năm trăm vị, đã đến Setabyā và đang trú ở rừng cây siṁsapā phía bắc Setabyā. ",
  "dn23:3.6": "Vị Tôn giả Kumārakassapa ấy được tiếng tốt đồn xa như sau: ",
  "dn23:3.7": "“Là bậc hiền trí, thông đạt, thông minh, đa văn, khéo thuyết pháp, biện tài tốt đẹp, trưởng lão và là bậc A-la-hán.” ",
  "dn23:3.8": "Họ đang đi đến để yết kiến Tôn giả Kumārakassapa ấy.’ ",
  "dn23:3.9": "‘Vậy này khanh, hãy đến chỗ các Bà-la-môn và gia chủ ở Setabyā; đến rồi hãy nói với họ như sau: ",
  "dn23:3.10": "“Này chư vị, vương tử Pāyāsi nói như vầy—",
  "dn23:3.11": "xin chư vị hãy đợi, vì vương tử Pāyāsi cũng sẽ đi đến yết kiến sa-môn Kumārakassapa.” ",
  "dn23:3.12": "Trước khi sa-môn Kumārakassapa thuyết phục các Bà-la-môn và gia chủ ở Setabyā, những người ngu si, chưa thông đạt, rằng: ",
  "dn23:3.13": "“Có đời sau, có chúng sinh hóa sinh, có quả báo dị thục của các nghiệp thiện và ác.” ",
  "dn23:3.14": "Vì này khanh, không có đời sau, không có chúng sinh hóa sinh, không có quả báo dị thục của các nghiệp thiện và ác.’ ",
  "dn23:3.15": "‘Vâng, thưa ngài,’ người hầu cận ấy đáp lời vương tử Pāyāsi, rồi đi đến chỗ các Bà-la-môn và gia chủ ở Setabyā; đến rồi nói với họ rằng: ",
  "dn23:3.16": "‘Này chư vị, vương tử Pāyāsi nói như vầy: xin chư vị hãy đợi, vì vương tử Pāyāsi cũng sẽ đi đến yết kiến sa-môn Kumārakassapa.’ ",
  "dn23:4.1": "Rồi vương tử Pāyāsi, được các Bà-la-môn và gia chủ ở Setabyā vây quanh, đi đến rừng cây siṁsapā, đến chỗ Tôn giả Kumārakassapa; đến nơi, nói lời chào hỏi thân thiện với Tôn giả Kumārakassapa, sau khi nói những lời thăm hỏi xã giao đáng ghi nhớ, liền ngồi xuống một bên. ",
  "dn23:4.2": "Các Bà-la-môn và gia chủ ở Setabyā, một số đảnh lễ Tôn giả Kumārakassapa rồi ngồi xuống một bên; ",
  "dn23:4.3": "một số chào hỏi thân thiện với Tôn giả Kumārakassapa; ",
  "dn23:4.4": "sau khi nói những lời thăm hỏi xã giao đáng ghi nhớ, liền ngồi xuống một bên. ",
  "dn23:4.5": "Một số chắp tay hướng về Tôn giả Kumārakassapa rồi ngồi xuống một bên. ",
  "dn23:4.6": "Một số xưng tên họ rồi ngồi xuống một bên. ",
  "dn23:4.7": "Một số im lặng ngồi xuống một bên. ",
  "dn23:5.0": "2. Thuyết không có ",
  "dn23:5.1": "Khi đã ngồi xuống một bên, vương tử Pāyāsi nói với Tôn giả Kumārakassapa như sau: ",
  "dn23:5.2": "‘Này Kassapa, tôi có chủ trương và kiến giải như vầy: ",
  "dn23:5.3": "“Không có đời sau, không có chúng sinh hóa sinh, không có quả báo dị thục của các nghiệp thiện và ác.”’ ",
  "dn23:5.4": "‘Này vương tử, ta chưa từng thấy hay nghe có ai chủ trương, kiến giải như vậy. ",
  "dn23:5.5": "Làm sao lại có thể nói rằng: ",
  "dn23:5.6": "“Không có đời sau, không có chúng sinh hóa sinh, không có quả báo dị thục của các nghiệp thiện và ác” được? ",
  "dn23:5.7.0": "2.1. Ví dụ mặt trăng và mặt trời ",
  "dn23:5.8": "Vậy này vương tử, ở đây ta sẽ hỏi lại chính điều ấy; tùy theo điều nào hợp với ông, ông hãy trả lời điều ấy. ",
  "dn23:5.9": "Ông nghĩ thế nào, này vương tử, ",
  "dn23:5.10": "mặt trăng và mặt trời này thuộc thế giới này hay thế giới khác, là chư thiên hay loài người?’ ",
  "dn23:5.11": "‘Này Kassapa, mặt trăng và mặt trời này thuộc thế giới khác, không thuộc thế giới này; chúng là chư thiên, không phải loài người.’ ",
  "dn23:5.12": "“Thưa vương tử, cũng do cách này mà ngài nên nghĩ như sau—",
  "dn23:5.13": "‘quả thật có đời sau, có chúng sinh hóa sinh, có quả dị thục của các nghiệp lành và dữ.’”",
  "dn23:6.1": "“Dù Tôn giả Kassapa nói như vậy, nhưng ở đây tôi lại nghĩ thế này:",
  "dn23:6.2": "‘quả thật không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp lành và dữ.’”",
  "dn23:6.3": "“Nhưng này vương tử, có cách nào khiến ngài nghĩ như vậy chăng:",
  "dn23:6.4": "‘quả thật không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp lành và dữ’?”",
  "dn23:6.5": "“Có, thưa Tôn giả Kassapa, có cách khiến tôi nghĩ như vậy:",
  "dn23:6.6": "‘quả thật không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp lành và dữ.’”",
  "dn23:6.7": "“Như thế nào, thưa vương tử?”",
  "dn23:6.8": "“Ở đây, thưa Tôn giả Kassapa, tôi có những bạn bè, đại thần, bà con huyết thống sát sinh, lấy của không cho, tà hạnh trong các dục, nói dối, nói hai lưỡi, nói lời thô ác, nói lời phù phiếm, tham lam, tâm sân hận, tà kiến.",
  "dn23:6.9": "Về sau họ bị bệnh, khổ sở, trọng bệnh.",
  "dn23:6.10": "Khi tôi biết rằng:",
  "dn23:6.11": "‘nay họ sẽ không qua khỏi bệnh này’, thì tôi đến gần và nói như sau:",
  "dn23:6.12": "‘Thưa các vị, có một số sa-môn, bà-la-môn chủ trương và có kiến giải như sau:",
  "dn23:6.13": "“Những ai sát sinh, lấy của không cho, tà hạnh trong các dục, nói dối, nói hai lưỡi, nói lời thô ác, nói lời phù phiếm, tham lam, tâm sân hận, tà kiến, thì sau khi thân hoại mạng chung sẽ sinh vào cõi dữ, ác thú, đọa xứ, địa ngục.”",
  "dn23:6.14": "Các vị thì sát sinh, lấy của không cho, tà hạnh trong các dục, nói dối, nói hai lưỡi, nói lời thô ác, nói lời phù phiếm, tham lam, tâm sân hận, tà kiến.",
  "dn23:6.15": "Nếu lời nói của các sa-môn, bà-la-môn ấy là thật, thì sau khi thân hoại mạng chung, các vị sẽ sinh vào cõi dữ, ác thú, đọa xứ, địa ngục.",
  "dn23:6.16": "Nếu, thưa các vị, sau khi thân hoại mạng chung, các vị sinh vào cõi dữ, ác thú, đọa xứ, địa ngục, thì hãy đến báo cho tôi biết rằng:",
  "dn23:6.17": "“quả thật có đời sau, có chúng sinh hóa sinh, có quả dị thục của các nghiệp lành và dữ.”",
  "dn23:6.18": "Các vị là những người tôi tin cậy, đáng tin; điều gì các vị thấy, đúng như tự mình thấy, thì việc ấy sẽ là như vậy.’",
  "dn23:6.19": "Họ nhận lời tôi rằng ‘lành thay’, nhưng không đến báo cho tôi, cũng không sai sứ giả đến.",
  "dn23:6.20": "Đây cũng là một cách, thưa Tôn giả Kassapa, khiến tôi nghĩ như vậy:",
  "dn23:6.21": "‘quả thật không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp lành và dữ.’”",
  "dn23:7.0": "2.2. Ví dụ kẻ trộm",
  "dn23:7.1": "“Vậy thì, này vương tử, chính ở đây ta sẽ hỏi ngài. Ngài hãy trả lời theo điều ngài thấy thích hợp.",
  "dn23:7.2": "Ngài nghĩ thế nào, này vương tử,",
  "dn23:7.3": "ở đây người ta bắt được một tên trộm, kẻ làm ác, rồi dẫn đến cho ngài:",
  "dn23:7.4": "‘Thưa ngài, đây là tên trộm, kẻ làm ác của ngài;",
  "dn23:7.5": "ngài muốn xử phạt nó thế nào thì cứ xử.’",
  "dn23:7.6": "Rồi ngài nói như sau:",
  "dn23:7.7": "‘Vậy thì, này các ông, hãy trói chặt người này bằng dây thừng chắc, trói quặt tay ra sau, cạo đầu trọc, đánh trống ầm ĩ, dẫn đi từ đường này sang đường khác, từ ngã tư này sang ngã tư khác, rồi đưa ra cửa nam, đến pháp trường ở phía nam thành mà chém đầu nó.’",
  "dn23:7.8": "Họ nhận lệnh ‘vâng’, rồi trói chặt người ấy bằng dây thừng chắc, trói quặt tay ra sau, cạo đầu trọc, đánh trống ầm ĩ, dẫn đi từ đường này sang đường khác, từ ngã tư này sang ngã tư khác, rồi đưa ra cửa nam, đến pháp trường ở phía nam thành và bắt ngồi xuống.",
  "dn23:7.9": "Liệu tên trộm ấy có thể xin những người hành hình rằng:",
  "dn23:7.10": "‘Xin các ông hành hình hãy đợi một chút, ở làng hay thị trấn kia tôi có bạn bè, đại thần, bà con huyết thống; để tôi đến dặn dò họ rồi sẽ trở lại’, hay là ngay khi nó còn đang van xin, những người hành hình sẽ chém đầu nó?”",
  "dn23:7.11": "“Không đâu, thưa Tôn giả Kassapa, tên trộm ấy không thể xin những người hành hình rằng:",
  "dn23:7.12": "‘Xin các ông hành hình hãy đợi một chút, ở làng hay thị trấn kia tôi có bạn bè, đại thần, bà con huyết thống; để tôi đến dặn dò họ rồi sẽ trở lại.’",
  "dn23:7.13": "Trái lại, ngay khi nó còn đang van xin, những người hành hình sẽ chém đầu nó.”",
  "dn23:7.14": "“Một tên trộm là con người, đối với những người hành hình là con người, còn không thể xin rằng:",
  "dn23:7.15": "‘Xin các ông hành hình hãy đợi một chút, ở làng hay thị trấn kia tôi có bạn bè, đại thần, bà con huyết thống; để tôi đến dặn dò họ rồi sẽ trở lại.’",
  "dn23:7.16": "Huống nữa những bạn bè, đại thần, bà con huyết thống của ngài, là những người sát sinh, lấy của không cho, tà hạnh trong các dục, nói dối, nói hai lưỡi, nói lời thô ác, nói lời phù phiếm, tham lam, tâm sân hận, tà kiến, sau khi thân hoại mạng chung sinh vào cõi dữ, ác thú, đọa xứ, địa ngục, liệu họ có thể xin các ngục tốt rằng:",
  "dn23:7.17": "‘Xin các ngục tốt hãy đợi một chút, để chúng tôi đến báo cho vương tử Pāyāsi biết rằng:",
  "dn23:7.18": "“quả thật có đời sau, có chúng sinh hóa sinh, có quả dị thục của các nghiệp lành và dữ”’ chăng?",
  "dn23:7.19": "Thưa vương tử, cũng do cách này mà ngài nên nghĩ như sau:",
  "dn23:7.20": "‘quả thật có đời sau, có chúng sinh hóa sinh, có quả dị thục của các nghiệp lành và dữ.’”",
  "dn23:8.1": "“Dù Tôn giả Kassapa nói như vậy, nhưng ở đây tôi lại nghĩ thế này:",
  "dn23:8.2": "‘quả thật không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp lành và dữ.’”",
  "dn23:8.3": "“Nhưng này vương tử, có cách nào khiến ngài nghĩ như vậy chăng:",
  "dn23:8.4": "‘quả thật không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp lành và dữ’?”",
  "dn23:8.5": "“Có, thưa Tôn giả Kassapa, có cách khiến tôi nghĩ như vậy:",
  "dn23:8.6": "‘quả thật không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp lành và dữ.’”",
  "dn23:8.7": "“Thưa vương tử, như thế nào?”",
  "dn23:8.8": "“Ở đây, này Kassapa, các bạn bè, đại thần, bà con huyết thống của tôi từ bỏ sát sinh, từ bỏ lấy của không cho, từ bỏ tà hạnh trong các dục, từ bỏ nói dối, từ bỏ nói lời chia rẽ, từ bỏ nói lời thô ác, từ bỏ nói lời phù phiếm, không tham lam, không ôm lòng sân hận, có chánh kiến.",
  "dn23:8.9": "Về sau, họ bị bệnh, đau đớn, bệnh nặng trầm trọng.",
  "dn23:8.10": "Khi tôi biết rằng:",
  "dn23:8.11": "‘nay họ sẽ không qua khỏi bệnh này’, thì tôi đến gần và nói như sau:",
  "dn23:8.12": "‘Này các vị, có một số sa-môn, bà-la-môn chủ trương như vầy, có kiến giải như vầy:",
  "dn23:8.13": "“Những ai từ bỏ sát sinh, từ bỏ lấy của không cho, từ bỏ tà hạnh trong các dục, từ bỏ nói dối, từ bỏ nói lời chia rẽ, từ bỏ nói lời thô ác, từ bỏ nói lời phù phiếm, không tham lam, không ôm lòng sân hận, có chánh kiến, thì sau khi thân hoại mạng chung sẽ sinh vào cõi lành, cõi trời.”",
  "dn23:8.14": "Các vị quả thật là những người từ bỏ sát sinh, từ bỏ lấy của không cho, từ bỏ tà hạnh trong các dục, từ bỏ nói dối, từ bỏ nói lời chia rẽ, từ bỏ nói lời thô ác, từ bỏ nói lời phù phiếm, không tham lam, không ôm lòng sân hận, có chánh kiến.",
  "dn23:8.15": "Nếu lời nói của các sa-môn, bà-la-môn ấy là chân thật, thì các vị sau khi thân hoại mạng chung sẽ sinh vào cõi lành, cõi trời.",
  "dn23:8.16": "Này các vị, nếu sau khi thân hoại mạng chung, các vị sinh vào cõi lành, cõi trời, thì hãy đến báo cho tôi biết rằng:",
  "dn23:8.17": "“Quả thật có đời sau, có các chúng sinh hóa sinh, có quả và dị thục của các nghiệp lành và dữ.”",
  "dn23:8.18": "Các vị lại là những người đáng tin, đáng làm chứng cho tôi; điều gì các vị thấy, đúng như tự mình thấy, thì hẳn là như vậy.’",
  "dn23:8.19": "Họ nhận lời tôi rằng ‘lành thay’, nhưng rồi không đến báo cho tôi, cũng không sai sứ giả đến.",
  "dn23:8.20": "Này Kassapa, đây cũng là một cách khiến tôi nghĩ rằng:",
  "dn23:8.21": "‘Quả thật không có đời sau, không có chúng sinh hóa sinh, không có quả và dị thục của các nghiệp lành và dữ.’”",
  "dn23:9.0": "2.3. Ví dụ người trong hố phân",
  "dn23:9.1": "“Vậy thì, thưa vương tử, ta sẽ nêu cho ông một ví dụ.",
  "dn23:9.2": "Nhờ ví dụ, ở đây có những người trí hiểu được ý nghĩa lời nói.",
  "dn23:9.3": "Ví như, thưa vương tử, có một người bị chìm ngập trong hố phân đến tận đầu.",
  "dn23:9.4": "Rồi ông ra lệnh cho người ta:",
  "dn23:9.5": "‘Này các ông, vậy hãy kéo người ấy ra khỏi hố phân đó.’",
  "dn23:9.6": "Họ đáp ‘lành thay’ rồi kéo người ấy ra khỏi hố phân đó.",
  "dn23:9.7": "Rồi ông lại nói như sau:",
  "dn23:9.8": "‘Này các ông, vậy hãy dùng que tre cạo sạch phân trên thân người ấy cho thật kỹ.’",
  "dn23:9.9": "Họ đáp ‘lành thay’ rồi dùng que tre cạo sạch phân trên thân người ấy cho thật kỹ.",
  "dn23:9.10": "Rồi ông lại nói như sau:",
  "dn23:9.11": "‘Này các ông, vậy hãy lấy đất sét trắng chà xát thân người ấy thật kỹ ba lần.’",
  "dn23:9.12": "Họ liền lấy đất sét trắng chà xát thân người ấy thật kỹ ba lần.",
  "dn23:9.13": "Rồi ông lại nói như sau:",
  "dn23:9.14": "‘Này các ông, vậy hãy xức dầu cho người ấy và dùng bột mịn tắm rửa thật sạch ba lần.’",
  "dn23:9.15": "Họ liền xức dầu cho người ấy và dùng bột mịn tắm rửa thật sạch ba lần.",
  "dn23:9.16": "Rồi ông lại nói như sau:",
  "dn23:9.17": "‘Này các ông, vậy hãy cắt tóc và cạo râu cho người ấy.’",
  "dn23:9.18": "Họ liền cắt tóc và cạo râu cho người ấy.",
  "dn23:9.19": "Rồi ông lại nói như sau:",
  "dn23:9.20": "‘Này các ông, vậy hãy đem đến cho người ấy vòng hoa quý giá, hương xoa quý giá và y phục quý giá.’",
  "dn23:9.21": "Họ liền đem đến cho người ấy vòng hoa quý giá, hương xoa quý giá và y phục quý giá.",
  "dn23:9.22": "Rồi ông lại nói như sau:",
  "dn23:9.23": "‘Này các ông, vậy hãy đưa người ấy lên lầu và bày đủ năm món dục lạc cho người ấy.’",
  "dn23:9.24": "Họ liền đưa người ấy lên lầu và bày đủ năm món dục lạc cho người ấy.",
  "dn23:9.25": "Thưa vương tử, ông nghĩ thế nào,",
  "dn23:9.26": "người ấy, sau khi đã tắm sạch, xức thơm, cắt sửa tóc râu gọn gàng, đeo vòng hoa trang sức, mặc y phục trắng sạch, ở trên lầu cao đẹp, được đầy đủ và hưởng thụ năm món dục lạc, có còn muốn lại chìm xuống hố phân ấy nữa chăng?”",
  "dn23:9.27": "“Không đâu, này Kassapa.”",
  "dn23:9.28": "“Vì sao vậy?”",
  "dn23:9.29": "“Vì hố phân là nhơ uế, này Kassapa, vừa nhơ uế vừa bị xem là nhơ uế, vừa hôi thối vừa bị xem là hôi thối, vừa ghê tởm vừa bị xem là ghê tởm, vừa đáng chán ghét vừa bị xem là đáng chán ghét.”",
  "dn23:9.30": "“Cũng vậy, thưa vương tử, loài người đối với chư thiên là nhơ uế và bị xem là nhơ uế, hôi thối và bị xem là hôi thối, ghê tởm và bị xem là ghê tởm, đáng chán ghét và bị xem là đáng chán ghét.",
  "dn23:9.31": "Thưa vương tử, mùi của loài người làm chư thiên khó chịu trong phạm vi một trăm do-tuần.",
  "dn23:9.32": "Huống nữa, các bạn bè, đại thần, bà con huyết thống của ông, những người từ bỏ sát sinh, từ bỏ lấy của không cho, từ bỏ tà hạnh trong các dục, từ bỏ nói dối, từ bỏ nói lời chia rẽ, từ bỏ nói lời thô ác, từ bỏ nói lời phù phiếm, không tham lam, không ôm lòng sân hận, có chánh kiến, sau khi thân hoại mạng chung sinh vào cõi lành, cõi trời, lẽ nào họ lại đến báo cho ông rằng:",
  "dn23:9.33": "‘Quả thật có đời sau, có các chúng sinh hóa sinh, có quả và dị thục của các nghiệp lành và dữ’ sao?",
  "dn23:9.34": "Ngay bằng cách này nữa, thưa vương tử, ông cũng nên hiểu như vậy:",
  "dn23:9.35": "‘cũng có đời sau, có các chúng sinh hóa sinh, có quả và dị thục của các nghiệp lành và dữ’.”",
  "dn23:10.1": "“Dù tôn giả Kassapa nói như vậy, nhưng ở đây tôi lại nghĩ thế này:",
  "dn23:10.2": "‘cũng không có đời sau, không có các chúng sinh hóa sinh, không có quả và dị thục của các nghiệp lành và dữ’.”",
  "dn23:10.3": "“Nhưng này vương tử, có một trường hợp…",
  "dn23:10.4": "“Có, thưa Kassapa, có một trường hợp…",
  "dn23:10.5": "“Như thế nào, này vương tử?”",
  "dn23:10.6": "“Ở đây, thưa Kassapa, các bạn bè, đại thần, bà con huyết thống của tôi từ bỏ sát sinh, từ bỏ lấy của không cho, từ bỏ tà hạnh trong các dục, từ bỏ nói dối, từ bỏ các chỗ say sưa do rượu men rượu nấu đưa đến phóng dật,",
  "dn23:10.7": "về sau họ bị bệnh, khổ sở, trọng bệnh.",
  "dn23:10.8": "Khi tôi biết rằng:",
  "dn23:10.9": "‘nay họ sẽ không qua khỏi bệnh này’, thì tôi đến gần và nói với họ như sau:",
  "dn23:10.10": "‘Có những sa-môn, bà-la-môn chủ trương như vầy, có kiến giải như vầy:",
  "dn23:10.11": "“những ai từ bỏ sát sinh, từ bỏ lấy của không cho, từ bỏ tà hạnh trong các dục, từ bỏ nói dối, từ bỏ các chỗ say sưa do rượu men rượu nấu đưa đến phóng dật, thì sau khi thân hoại mạng chung sẽ sinh vào cõi lành, cõi trời, thế giới chư thiên, cùng ở với chư thiên cõi Ba Mươi Ba.”",
  "dn23:10.12": "Quý vị quả thật là những người từ bỏ sát sinh, từ bỏ lấy của không cho, từ bỏ tà hạnh trong các dục, từ bỏ nói dối, từ bỏ các chỗ say sưa do rượu men rượu nấu đưa đến phóng dật.",
  "dn23:10.13": "Nếu lời nói của các sa-môn, bà-la-môn ấy là thật, thì quý vị sau khi thân hoại mạng chung sẽ sinh vào cõi lành, cõi trời, thế giới chư thiên, cùng ở với chư thiên cõi Ba Mươi Ba.",
  "dn23:10.14": "Nếu, thưa quý vị, sau khi thân hoại mạng chung, quý vị sinh vào cõi lành, cõi trời, thế giới chư thiên, cùng ở với chư thiên cõi Ba Mươi Ba, thì hãy từ đó đến báo cho tôi biết rằng:",
  "dn23:10.15": "“cũng có đời sau, có các chúng sinh hóa sinh, có quả và dị thục của các nghiệp lành và dữ.”",
  "dn23:10.16": "Quý vị là những người đáng tin, đáng làm chứng cho tôi; điều gì quý vị đã thấy, đúng như tự mình thấy, thì hẳn là như vậy.’",
  "dn23:10.17": "Họ nhận lời với tôi rằng: ‘Lành thay’, nhưng rồi không đến báo cho tôi, cũng không sai sứ giả đến.",
  "dn23:10.18": "Đây cũng là một trường hợp, thưa Kassapa, do trường hợp này mà tôi nghĩ rằng:",
  "dn23:10.19": "‘cũng không có đời sau, không có các chúng sinh hóa sinh, không có quả và dị thục của các nghiệp lành và dữ’.”",
  "dn23:11.0": "2.4. Ví dụ về chư thiên cõi Ba Mươi Ba",
  "dn23:11.1": "“Vậy thì, này vương tử, chính ở đây ta sẽ hỏi lại ông; ông thấy thế nào thích hợp thì hãy trả lời như vậy.",
  "dn23:11.2": "Này vương tử, một trăm năm ở loài người là một ngày một đêm của chư thiên cõi Ba Mươi Ba; ba mươi ngày đêm như vậy là một tháng; mười hai tháng như vậy là một năm; một ngàn năm chư thiên như vậy là thọ lượng của chư thiên cõi Ba Mươi Ba.",
  "dn23:11.3": "Những người bạn bè, đại thần, bà con huyết thống của ông, những người từ bỏ sát sinh, từ bỏ lấy của không cho, từ bỏ tà hạnh trong các dục, từ bỏ nói dối, từ bỏ các chỗ say sưa do rượu men rượu nấu đưa đến phóng dật, sau khi thân hoại mạng chung đã sinh vào cõi lành, cõi trời, thế giới chư thiên, cùng ở với chư thiên cõi Ba Mươi Ba.",
  "dn23:11.4": "Nếu họ nghĩ như vầy:",
  "dn23:11.5": "‘hãy để chúng tôi hưởng thụ đầy đủ, sung mãn năm món dục lạc cõi trời trong hai hay ba ngày đêm cõi trời, rồi chúng tôi sẽ đến báo cho vương tử Pāyāsi biết rằng:",
  "dn23:11.6": "“cũng có đời sau, có các chúng sinh hóa sinh, có quả và dị thục của các nghiệp lành và dữ.”",
  "dn23:11.7": "Thì liệu họ có đến báo cho ông rằng—",
  "dn23:11.8": "“cũng có đời sau, có các chúng sinh hóa sinh, có quả và dị thục của các nghiệp lành và dữ” không?”",
  "dn23:11.9": "“Không đâu, thưa Kassapa.",
  "dn23:11.10": "Vì khi ấy, thưa Kassapa, có lẽ chúng tôi đã chết từ lâu rồi.",
  "dn23:11.11": "Nhưng ai là người báo cho tôn giả Kassapa biết rằng:",
  "dn23:11.12": "‘có chư thiên cõi Ba Mươi Ba’ hay ‘chư thiên cõi Ba Mươi Ba có thọ mạng dài như vậy’?",
  "dn23:11.13": "Chúng tôi không tin tôn giả Kassapa khi tôn giả nói rằng:",
  "dn23:11.14": "‘có chư thiên cõi Ba Mươi Ba’ hay ‘chư thiên cõi Ba Mươi Ba có thọ mạng dài như vậy’.”",
  "dn23:11.15.0": "2.5. Ví dụ người mù bẩm sinh",
  "dn23:11.16": "“Ví như, này vương tử, một người mù bẩm sinh không thấy các sắc đen trắng, không thấy các sắc xanh, không thấy các sắc vàng, không thấy các sắc đỏ, không thấy các sắc đỏ sẫm, không thấy chỗ bằng chỗ không bằng, không thấy các vì sao, không thấy mặt trăng và mặt trời.",
  "dn23:11.17": "Người ấy nói như vầy:",
  "dn23:11.18": "‘Không có các sắc đen trắng, không có người thấy các sắc đen trắng.",
  "dn23:11.19": "Không có các sắc xanh, không có người thấy các sắc xanh.",
  "dn23:11.20": "Không có các sắc vàng, không có người thấy các sắc vàng.",
  "dn23:11.21": "Không có các sắc đỏ, không có người thấy các sắc đỏ.",
  "dn23:11.22": "Không có các sắc đỏ sẫm, không có người thấy các sắc đỏ sẫm.",
  "dn23:11.23": "Không có chỗ bằng chỗ không bằng, không có người thấy chỗ bằng chỗ không bằng.",
  "dn23:11.24": "Không có các vì sao, không có người thấy các vì sao.",
  "dn23:11.25": "Không có mặt trăng và mặt trời, không có người thấy mặt trăng và mặt trời.",
  "dn23:11.26": "Tôi không biết điều ấy, tôi không thấy điều ấy, nên điều ấy không có.’",
  "dn23:11.27": "Này vương tử, người ấy nói như vậy có đúng chăng?”",
  "dn23:11.28": "“Không đâu, thưa Kassapa.",
  "dn23:11.29": "Có các sắc đen trắng, có người thấy các sắc đen trắng.”",
  "dn23:11.30": "Có những sắc màu xanh, có người thấy được các sắc màu xanh ấy …",
  "dn23:11.31": "có cái bằng phẳng và gồ ghề, có người thấy được cái bằng phẳng và gồ ghề ấy.",
  "dn23:11.32": "Có những sắc tướng của các vì sao, có người thấy được các sắc tướng của các vì sao ấy.",
  "dn23:11.33": "Có mặt trăng và mặt trời, có người thấy được mặt trăng và mặt trời ấy.",
  "dn23:11.34": "‘Ta không biết điều ấy, ta không thấy điều ấy, nên điều ấy không có.’",
  "dn23:11.35": "Này Kassapa, người ấy nói như vậy thì không phải là nói đúng.”",
  "dn23:11.36": "“Cũng vậy, này vị vương tử, ta nghĩ ông hiện ra như người mù bẩm sinh khi ông nói với ta như vậy.",
  "dn23:11.37": "Ai báo cho tôn giả Kassapa biết rằng:",
  "dn23:11.38": "‘có chư thiên ở cõi Tam thập tam’ hay ‘chư thiên ở cõi Tam thập tam sống lâu đến như vậy’?",
  "dn23:11.39": "Chúng tôi không tin tôn giả Kassapa khi nói rằng:",
  "dn23:11.40": "‘có chư thiên ở cõi Tam thập tam’ hay ‘chư thiên ở cõi Tam thập tam sống lâu đến như vậy’.”",
  "dn23:11.41": "“Này vị vương tử, đời sau không thể được thấy như ông nghĩ, bằng con mắt thịt này.",
  "dn23:11.42": "Này vị vương tử, những sa-môn, bà-la-môn nào sống nơi rừng núi, chốn hoang vắng, trú xứ thanh tịnh,",
  "dn23:11.43": "ở đó họ sống không phóng dật, nhiệt tâm, chuyên chú, và thanh lọc thiên nhãn. Với thiên nhãn thanh tịnh, siêu vượt loài người, họ thấy cả thế giới này lẫn thế giới khác, và các chúng sinh hóa sinh.",
  "dn23:11.44": "Này vị vương tử, đời sau phải được thấy như vậy;",
  "dn23:11.45": "chứ không phải như ông nghĩ, bằng con mắt thịt này.",
  "dn23:11.46": "Ngay theo phương diện này nữa, này vị vương tử, phải kết luận rằng:",
  "dn23:11.47": "‘quả thật có đời sau, có các chúng sinh hóa sinh, có quả và dị thục của các nghiệp thiện và ác.’”",
  "dn23:12.1": "“Dù tôn giả Kassapa nói như vậy, nhưng ở đây tôi lại nghĩ thế này:",
  "dn23:12.2": "‘cũng có thể không có đời sau, không có các chúng sinh hóa sinh, không có quả và dị thục của các nghiệp thiện và ác.’”",
  "dn23:12.3": "“Nhưng này vị vương tử, có một phương diện khác …",
  "dn23:12.4": "“Có, này Kassapa, có một phương diện khác …",
  "dn23:12.5": "như thế nào, này vị vương tử?”",
  "dn23:12.6": "“Này Kassapa, ở đây tôi thấy những sa-môn, bà-la-môn có giới hạnh, có pháp lành, muốn sống, không muốn chết, muốn an lạc, ghét khổ đau.",
  "dn23:12.7": "Này Kassapa, tôi nghĩ như vầy—",
  "dn23:12.8": "nếu những vị sa-môn, bà-la-môn có giới hạnh, có pháp lành ấy biết rõ rằng:",
  "dn23:12.9": "‘sau khi chết ở đây, chúng ta sẽ được tốt đẹp hơn’,",
  "dn23:12.10": "thì nay những vị sa-môn, bà-la-môn có giới hạnh, có pháp lành ấy đã ăn thuốc độc, hoặc dùng dao tự sát, hoặc treo cổ mà chết, hoặc gieo mình xuống vực rồi.",
  "dn23:12.11": "Nhưng vì những vị sa-môn, bà-la-môn có giới hạnh, có pháp lành ấy không biết như vậy rằng:",
  "dn23:12.12": "‘sau khi chết ở đây, chúng ta sẽ được tốt đẹp hơn’, nên họ muốn sống, không muốn chết, muốn an lạc, ghét khổ đau, và không tự giết mình.",
  "dn23:12.13": "Đây cũng là một phương diện, này Kassapa, theo đó tôi nghĩ rằng:",
  "dn23:12.14": "‘cũng có thể không có đời sau, không có các chúng sinh hóa sinh, không có quả và dị thục của các nghiệp thiện và ác.’”",
  "dn23:13.0": "2.6. Ví dụ người đàn bà mang thai",
  "dn23:13.1": "“Vậy thì, này vị vương tử, ta sẽ nêu cho ông một ví dụ.",
  "dn23:13.2": "Nhờ ví dụ, ở đây có những người có trí hiểu được ý nghĩa lời nói.",
  "dn23:13.3": "Thuở xưa, này vị vương tử, có một bà-la-môn nọ có hai người vợ.",
  "dn23:13.4": "Một người có con trai chừng mười hoặc mười hai tuổi, người kia đang mang thai gần đến ngày sinh.",
  "dn23:13.5": "Rồi bà-la-môn ấy qua đời.",
  "dn23:13.6": "Bấy giờ cậu thiếu niên ấy nói với mẹ kế rằng:",
  "dn23:13.7": "‘Này bà, tài sản, lúa thóc, bạc hay vàng nào ở đây, tất cả đều là của tôi;",
  "dn23:13.8": "bà không có phần gì trong đó.",
  "dn23:13.9": "Này bà, hãy giao lại cho tôi phần gia tài của cha tôi.’",
  "dn23:13.10": "Khi được nói vậy, người đàn bà bà-la-môn ấy nói với cậu thiếu niên rằng:",
  "dn23:13.11": "‘Con hãy chờ một chút, này con, cho đến khi ta sinh nở.",
  "dn23:13.12": "Nếu là con trai, nó cũng sẽ có một phần;",
  "dn23:13.13": "nếu là con gái, nó cũng sẽ thuộc quyền con hưởng dùng.’",
  "dn23:13.14": "Lần thứ hai, cậu thiếu niên ấy lại nói với mẹ kế rằng:",
  "dn23:13.15": "‘Này bà, tài sản, lúa thóc, bạc hay vàng nào ở đây, tất cả đều là của tôi;",
  "dn23:13.16": "bà không có phần gì trong đó.",
  "dn23:13.17": "Này bà, hãy giao lại cho tôi phần gia tài của cha tôi.’",
  "dn23:13.18": "Lần thứ hai, người bà-la-môn ấy nói với chàng thanh niên đó rằng:",
  "dn23:13.19": "‘Con hãy chờ đã, con, cho đến khi mẹ sinh nở.",
  "dn23:13.20": "Nếu là con trai, thì nó cũng sẽ có một phần;",
  "dn23:13.21": "nếu là con gái, thì nó cũng sẽ thuộc quyền hưởng dụng của con.’",
  "dn23:13.22": "Lần thứ ba, chàng thanh niên ấy nói với người mẹ kế rằng:",
  "dn23:13.23": "‘Thưa bà, tài sản này, dù là của cải, lúa thóc, bạc hay vàng, tất cả đều là của tôi;",
  "dn23:13.24": "ở đây không có gì là của bà.",
  "dn23:13.25": "Thưa bà, hãy giao phần gia tài của cha tôi cho tôi.’",
  "dn23:13.26": "Bấy giờ, người bà-la-môn ấy cầm dao đi vào phòng kín rồi rạch bụng mình:",
  "dn23:13.27": "‘cho đến khi ta sinh nở, dù là con trai hay con gái.’",
  "dn23:13.28": "Bà ấy đã hủy hoại chính mình, mạng sống, bào thai và tài sản.",
  "dn23:13.29": "Cũng như kẻ ngu si, thiếu hiểu biết, rơi vào bất hạnh tai họa, tìm kiếm gia tài một cách phi lý; cũng vậy, này vương tử, ông là kẻ ngu si, thiếu hiểu biết, sẽ rơi vào bất hạnh tai họa khi tìm kiếm đời sau một cách phi lý;",
  "dn23:13.30": "giống như người bà-la-môn ấy, ngu si, thiếu hiểu biết, rơi vào bất hạnh tai họa, tìm kiếm gia tài một cách phi lý.",
  "dn23:13.31": "Này vương tử, các sa-môn, bà-la-môn có giới hạnh, có thiện pháp không làm cho cái chưa chín phải chín ép;",
  "dn23:13.32": "trái lại, họ chờ cho chín muồi.",
  "dn23:13.33": "Vì mạng sống của các sa-môn, bà-la-môn có giới hạnh, có thiện pháp là điều có ích cho những người có trí, này vương tử.",
  "dn23:13.34": "Này vương tử, các sa-môn, bà-la-môn có giới hạnh, có thiện pháp càng tồn tại lâu dài bao nhiêu thì càng tạo ra nhiều phước báu bấy nhiêu, và hành trì vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng thế gian, vì lợi ích, an lạc cho chư thiên và loài người.",
  "dn23:13.35": "Cũng theo cách này nữa, này vương tử, ông nên nghĩ rằng:",
  "dn23:13.36": "‘Quả thật có đời sau, có các chúng sinh hóa sinh, có kết quả và dị thục của các nghiệp lành và dữ.’",
  "dn23:14.1": "‘Dù ngài Kassapa nói như vậy, nhưng ở đây tôi vẫn nghĩ thế này:",
  "dn23:14.2": "“Quả thật không có đời sau, không có chúng sinh hóa sinh, không có kết quả và dị thục của các nghiệp lành và dữ.”’",
  "dn23:14.3": "‘Nhưng này vương tử, có một cách…",
  "dn23:14.4": "‘Có đấy, thưa Kassapa, một cách…",
  "dn23:14.5": "như thế nào vậy, này vương tử?’",
  "dn23:14.6": "‘Ở đây, thưa Kassapa, người ta bắt được một tên trộm, kẻ làm ác, rồi dẫn đến cho tôi:",
  "dn23:14.7": "“Bạch ngài, đây là tên trộm, kẻ làm ác này;",
  "dn23:14.8": "ngài muốn xử phạt nó thế nào thì cứ xử.”",
  "dn23:14.9": "Tôi nói như sau:",
  "dn23:14.10": "“Vậy thì, này các ông, hãy bỏ người này còn sống vào trong một cái vạc, đậy kín miệng lại, buộc chặt bằng da tươi, trét dày bằng đất sét ướt, đặt lên lò rồi đốt lửa.”",
  "dn23:14.11": "Họ đáp với tôi: “Vâng”, rồi bỏ người ấy còn sống vào trong vạc, đậy kín miệng lại, buộc chặt bằng da tươi, trét dày bằng đất sét ướt, đặt lên lò rồi đốt lửa.",
  "dn23:14.12": "Khi chúng tôi biết rằng “người ấy đã chết”, thì hạ cái vạc xuống, đập vỡ ra, mở miệng vạc và nhìn kỹ từng chút một:",
  "dn23:14.13": "“Mong sao chúng ta có thể thấy sinh mạng của nó đi ra.”",
  "dn23:14.14": "Nhưng chúng tôi không thấy sinh mạng của nó đi ra.",
  "dn23:14.15": "Đây cũng là một cách, thưa Kassapa, do cách ấy mà tôi nghĩ rằng:",
  "dn23:14.16": "“Quả thật không có đời sau, không có chúng sinh hóa sinh, không có kết quả và dị thục của các nghiệp lành và dữ.”’",
  "dn23:15.0": "2.7. Ví dụ về giấc mộng",
  "dn23:15.1": "‘Vậy thì, này vương tử, chính về việc ấy ta sẽ hỏi lại ông; ông thấy thế nào thích hợp thì hãy trả lời như vậy.",
  "dn23:15.2": "Này vương tử, ông có nhớ rằng khi nằm nghỉ ban ngày, ông từng thấy trong mộng những khu vườn đáng yêu, những rừng cây đáng yêu, những vùng đất đáng yêu, những ao hồ đáng yêu không?’",
  "dn23:15.3": "‘Thưa Kassapa, tôi nhớ rằng khi nằm nghỉ ban ngày, tôi từng thấy trong mộng những khu vườn đáng yêu, những rừng cây đáng yêu, những vùng đất đáng yêu, những ao hồ đáng yêu.’",
  "dn23:15.4": "‘Khi ấy có phải những người lưng gù, người lùn, nữ hầu và các thiếu nữ canh giữ ông không?’",
  "dn23:15.5": "‘Đúng vậy, thưa Kassapa, khi ấy những người lưng gù, người lùn, nữ hầu và các thiếu nữ canh giữ tôi.’",
  "dn23:15.6": "‘Nhưng họ có thấy sinh mạng của ông đi vào hay đi ra không?’",
  "dn23:15.7": "‘Không, thưa Kassapa.’",
  "dn23:15.8": "‘Vậy thì, này vương tử, khi ông còn sống, những người sống ấy còn không thấy sinh mạng của ông đi vào hay đi ra.",
  "dn23:15.9": "Huống nữa làm sao ông có thể thấy sinh mạng của người đã chết đi vào hay đi ra?",
  "dn23:15.10": "Cũng theo cách này nữa, này vương tử, ông nên nghĩ rằng:",
  "dn23:15.11": "“Quả thật có đời sau, có các chúng sinh hóa sinh, có kết quả và dị thục của các nghiệp lành và dữ.”’",
  "dn23:16.1": "‘Dù ngài Kassapa nói như vậy, nhưng ở đây tôi vẫn nghĩ thế này:",
  "dn23:16.2": "“Quả thật không có đời sau, không có chúng sinh hóa sinh, không có kết quả và dị thục của các nghiệp lành và dữ.”’",
  "dn23:16.3": "‘Nhưng này vương tử, có một cách…’",
  "dn23:16.4": "“Có, này Kassapa, có một cách…",
  "dn23:16.5": "như thế nào vậy, thưa vương tử?”",
  "dn23:16.6": "“Ở đây, này Kassapa, người của tôi bắt được một tên trộm phạm tội rồi dẫn đến cho tôi:",
  "dn23:16.7": "‘Bạch ngài, đây là tên trộm phạm tội của ngài;",
  "dn23:16.8": "ngài muốn xử phạt nó thế nào thì cứ ra hình phạt ấy.’",
  "dn23:16.9": "Khi ấy tôi nói như vầy:",
  "dn23:16.10": "‘Vậy thì, này các ông, hãy cân người này khi còn sống trên bàn cân, rồi dùng dây siết cho chết ngạt, sau đó lại cân lần nữa.’",
  "dn23:16.11": "Họ đáp với tôi: ‘Vâng’, rồi cân người ấy khi còn sống trên bàn cân, dùng dây siết cho chết ngạt, rồi lại cân lần nữa.",
  "dn23:16.12": "Khi người ấy còn sống, thì nhẹ hơn, mềm hơn, và dễ sử dụng hơn.",
  "dn23:16.13": "Nhưng khi người ấy đã chết, thì nặng hơn, cứng đờ hơn, và khó sử dụng hơn.",
  "dn23:16.14": "Này Kassapa, đây cũng là một cách, do cách ấy mà đối với tôi có thể thành ra như vầy:",
  "dn23:16.15": "‘Quả thật không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp thiện và ác.’”",
  "dn23:17.0": "2.8. Ví dụ cục sắt nung đỏ",
  "dn23:17.1": "“Vậy thì, thưa vương tử, tôi sẽ nêu cho ngài một ví dụ.",
  "dn23:17.2": "Nhờ ví dụ, ở đây có những người trí hiểu được ý nghĩa của lời nói.",
  "dn23:17.3": "Ví như, thưa vương tử, một người đem cân trên bàn cân một cục sắt được nung nóng suốt ngày, đang cháy đỏ, bừng sáng.",
  "dn23:17.4": "Rồi vào một lúc khác, người ấy lại đem cân nó khi đã nguội lạnh, tắt hẳn.",
  "dn23:17.5": "Vậy khi nào cục sắt ấy nhẹ hơn, mềm hơn, và dễ sử dụng hơn: khi đang cháy đỏ, bừng sáng, hay khi đã nguội lạnh, tắt hẳn?”",
  "dn23:17.6": "“Này Kassapa, khi cục sắt ấy có kèm sức nóng và có kèm gió, đang cháy đỏ, bừng sáng, thì nó nhẹ hơn, mềm hơn, và dễ sử dụng hơn.",
  "dn23:17.7": "Nhưng khi cục sắt ấy không có kèm sức nóng, không có kèm gió, đã nguội lạnh, tắt hẳn, thì nó nặng hơn, cứng đờ hơn, và khó sử dụng hơn.”",
  "dn23:17.8": "“Cũng vậy, thưa vương tử, khi thân này có mạng sống, có hơi ấm, có thức, thì nó nhẹ hơn, mềm hơn, và dễ sử dụng hơn.",
  "dn23:17.9": "Nhưng khi thân này không có mạng sống, không có hơi ấm, không có thức, thì nó nặng hơn, cứng đờ hơn, và khó sử dụng hơn.",
  "dn23:17.10": "Ngay bằng cách này nữa, thưa vương tử, ngài nên đi đến kết luận như vầy:",
  "dn23:17.11": "‘Quả thật có đời sau, có chúng sinh hóa sinh, có quả dị thục của các nghiệp thiện và ác.’”",
  "dn23:18.1": "“Dù tôn giả Kassapa nói như vậy, nhưng ở đây tôi vẫn nghĩ như vầy:",
  "dn23:18.2": "‘Quả thật không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp thiện và ác.’”",
  "dn23:18.3": "“Nhưng, thưa vương tử, có một cách…",
  "dn23:18.4": "“Có, này Kassapa, có một cách…",
  "dn23:18.5": "như thế nào vậy, thưa vương tử?”",
  "dn23:18.6": "“Ở đây, này Kassapa, người của tôi bắt được một tên trộm phạm tội rồi dẫn đến cho tôi:",
  "dn23:18.7": "‘Bạch ngài, đây là tên trộm phạm tội của ngài;",
  "dn23:18.8": "ngài muốn xử phạt nó thế nào thì cứ ra hình phạt ấy.’",
  "dn23:18.9": "Khi ấy tôi nói như vầy:",
  "dn23:18.10": "‘Vậy thì, này các ông, hãy giết người này mà không làm tổn thương da, bì, thịt, gân, xương và tủy xương của nó; may ra chúng ta sẽ thấy mạng sống của nó đi ra chăng.’",
  "dn23:18.11": "Họ đáp với tôi: ‘Vâng’, rồi giết người ấy mà không làm tổn thương da… mạng sống.",
  "dn23:18.12": "Khi người ấy đã chết, tôi nói như vầy:",
  "dn23:18.13": "‘Vậy thì, này các ông, hãy đặt người này nằm ngửa ra, may ra chúng ta sẽ thấy mạng sống của nó đi ra chăng.’",
  "dn23:18.14": "Họ đặt người ấy nằm ngửa ra.",
  "dn23:18.15": "Nhưng chúng tôi không thấy mạng sống của nó đi ra.",
  "dn23:18.16": "Khi ấy tôi nói như vầy:",
  "dn23:18.17": "‘Vậy thì, này các ông, hãy đặt người này nằm sấp…",
  "dn23:18.18": "hãy đặt nằm nghiêng một bên…",
  "dn23:18.19": "hãy đặt nằm nghiêng bên kia…",
  "dn23:18.20": "hãy dựng đứng lên…",
  "dn23:18.21": "hãy chúc đầu xuống…",
  "dn23:18.22": "hãy đập bằng tay…",
  "dn23:18.23": "hãy ném đất đá vào…",
  "dn23:18.24": "hãy đánh bằng gậy…",
  "dn23:18.25": "hãy chém bằng vũ khí…",
  "dn23:18.26": "hãy lắc, rung, giũ nó, may ra chúng ta sẽ thấy mạng sống của nó đi ra chăng.’",
  "dn23:18.27": "Họ lắc người ấy, rung người ấy, giũ người ấy.",
  "dn23:18.28": "Nhưng chúng tôi không thấy mạng sống của người ấy đi ra.",
  "dn23:18.29": "Con mắt ấy vẫn còn đó, các sắc ấy vẫn còn đó, nhưng nó không cảm nhận cảnh giới ấy.",
  "dn23:18.30": "Lỗ tai ấy vẫn còn đó, các âm thanh ấy vẫn còn đó, nhưng nó không cảm nhận cảnh giới ấy.",
  "dn23:18.31": "Cái mũi ấy vẫn còn đó, các mùi ấy vẫn còn đó, nhưng nó không cảm nhận cảnh giới ấy.",
  "dn23:18.32": "Cái lưỡi ấy vẫn còn đó, các vị ấy vẫn còn đó, nhưng nó không cảm nhận cảnh giới ấy.",
  "dn23:18.33": "Thân ấy vẫn còn đó, các xúc chạm ấy vẫn còn đó, nhưng nó không cảm nhận cảnh giới ấy.",
  "dn23:18.34": "Này Kassapa, đây cũng là một cách lập luận, theo cách lập luận này mà tôi nghĩ rằng:",
  "dn23:18.35": "‘Cũng vậy, không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp thiện ác.’",
  "dn23:19.0": "2.9. Ví dụ về tiếng tù và",
  "dn23:19.1": "“Vậy thì, này vương tử, ta sẽ nêu cho ông một ví dụ.",
  "dn23:19.2": "Nhờ ví dụ, ở đây có những người trí hiểu được ý nghĩa của lời nói.",
  "dn23:19.3": "Thuở xưa, này vương tử, có một người thổi tù và cầm tù và đi đến một vùng biên địa.",
  "dn23:19.4": "Người ấy đi đến một ngôi làng nọ; đến nơi, đứng giữa làng, thổi tù và ba lần, rồi đặt tù và xuống đất và ngồi sang một bên.",
  "dn23:19.5": "Bấy giờ, này vương tử, những người ở vùng biên địa ấy nghĩ rằng:",
  "dn23:19.6": "‘Ô hay, âm thanh này là của ai mà quyến rũ như vậy, đáng ưa như vậy, say mê như vậy, trói buộc như vậy, mê hoặc như vậy?’",
  "dn23:19.7": "Họ tụ họp lại và nói với người thổi tù và ấy rằng:",
  "dn23:19.8": "‘Ô hay, âm thanh này là của ai mà quyến rũ như vậy, đáng ưa như vậy, say mê như vậy, trói buộc như vậy, mê hoặc như vậy?’",
  "dn23:19.9": "‘Này các vị, đây là cái tù và, âm thanh quyến rũ như vậy, đáng ưa như vậy, say mê như vậy, trói buộc như vậy, mê hoặc như vậy là của nó.’",
  "dn23:19.10": "Họ đặt cái tù và nằm ngửa xuống:",
  "dn23:19.11": "‘Nói đi, này tù và, nói đi, này tù và!’",
  "dn23:19.12": "Nhưng cái tù và ấy không phát ra âm thanh.",
  "dn23:19.13": "Họ đặt cái tù và úp xuống, đặt nghiêng sang một bên, đặt nghiêng sang bên kia, dựng lên, chúc đầu xuống, gõ bằng tay, gõ bằng cục đất, gõ bằng gậy, gõ bằng dao, lắc, rung, giũ nó:",
  "dn23:19.14": "‘Nói đi, này tù và, nói đi, này tù và!’",
  "dn23:19.15": "Nhưng cái tù và ấy không phát ra âm thanh.",
  "dn23:19.16": "Bấy giờ, này vương tử, người thổi tù và ấy nghĩ rằng:",
  "dn23:19.17": "‘Những người vùng biên địa này thật là ngu, làm sao họ lại tìm tiếng tù và một cách phi lý như thế được?’",
  "dn23:19.18": "Trong khi họ đang nhìn, ông ta cầm lấy cái tù và, thổi ba lần, rồi mang tù và đi mất.",
  "dn23:19.19": "Bấy giờ, này vương tử, những người ở vùng biên địa ấy nghĩ rằng:",
  "dn23:19.20": "‘Thì ra, này các vị, khi cái gọi là tù và này có người, có sự cố gắng, có hơi gió đi kèm, thì nó phát ra âm thanh; còn khi cái tù và này không có người, không có sự cố gắng, không có hơi gió đi kèm, thì nó không phát ra âm thanh.’",
  "dn23:19.21": "Cũng vậy, này vương tử, khi thân này có mạng sống, có hơi ấm, có thức đi kèm, thì nó đi tới, đi lui, đứng, ngồi, nằm; nó thấy sắc bằng mắt, nghe tiếng bằng tai, ngửi mùi bằng mũi, nếm vị bằng lưỡi, xúc chạm bằng thân, nhận biết các pháp bằng ý.",
  "dn23:19.22": "Còn khi thân này không có mạng sống, không có hơi ấm, không có thức đi kèm, thì nó không đi tới, không đi lui, không đứng, không ngồi, không nằm; không thấy sắc bằng mắt, không nghe tiếng bằng tai, không ngửi mùi bằng mũi, không nếm vị bằng lưỡi, không xúc chạm bằng thân, không nhận biết các pháp bằng ý.",
  "dn23:19.23": "Ngay cả theo cách lập luận này nữa, này vương tử, ông cũng nên nghĩ rằng:",
  "dn23:19.24": "‘Cũng vậy, có đời sau, có chúng sinh hóa sinh, có quả dị thục của các nghiệp thiện ác.’",
  "dn23:20.1": "“Dù tôn giả Kassapa nói như vậy, nhưng ở đây tôi vẫn nghĩ rằng:",
  "dn23:20.2": "‘Cũng vậy, không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp thiện ác.’",
  "dn23:20.3": "“Nhưng này vương tử, có một cách lập luận…",
  "dn23:20.4": "“Có, này Kassapa, có một cách lập luận…",
  "dn23:20.5": "“Như thế nào, này vương tử?”",
  "dn23:20.6": "“Ở đây, này Kassapa, người ta bắt được một tên trộm, kẻ làm ác, rồi dẫn đến cho tôi:",
  "dn23:20.7": "‘Bạch ngài, đây là tên trộm, kẻ làm ác của ngài,",
  "dn23:20.8": "ngài muốn xử phạt nó thế nào thì cứ xử.’",
  "dn23:20.9": "Tôi nói như vầy:",
  "dn23:20.10": "‘Vậy thì, này các ông, hãy rạch da người này ra, may ra chúng ta sẽ thấy được mạng sống của nó.’",
  "dn23:20.11": "Họ rạch da người ấy ra.",
  "dn23:20.12": "Nhưng chúng tôi không thấy mạng sống của nó.",
  "dn23:20.13": "Tôi lại nói như vầy:",
  "dn23:20.14": "‘Vậy thì, này các ông, hãy rạch da người này, cắt thịt, cắt gân, chẻ xương, chẻ tủy, may ra chúng ta sẽ thấy được mạng sống của nó.’",
  "dn23:20.15": "Họ chẻ tủy người ấy, nhưng chúng tôi vẫn không thấy mạng sống của nó.",
  "dn23:20.16": "Này Kassapa, đây cũng là một cách lập luận, theo cách lập luận này mà tôi nghĩ rằng:",
  "dn23:20.17": "‘Nghĩa là không có đời sau, không có chúng sinh hóa sinh, không có quả báo dị thục của các nghiệp thiện ác.’",
  "dn23:21.0": "2.10. Ví dụ người bện tóc thờ lửa",
  "dn23:21.1": "“Vậy thì, này vương tử, ta sẽ làm một ví dụ cho ngài.",
  "dn23:21.2": "Nhờ ví dụ, ở đây có những người trí hiểu được ý nghĩa của lời nói.",
  "dn23:21.3": "Thuở xưa, này vương tử, có một người bện tóc thờ lửa sống trong một am lá ở chốn rừng hoang.",
  "dn23:21.4": "Rồi, này vương tử, có một đoàn lữ hành đi qua một vùng quê nọ.",
  "dn23:21.5": "Rồi đoàn lữ hành ấy nghỉ lại một đêm gần am của người bện tóc thờ lửa ấy rồi ra đi.",
  "dn23:21.6": "Bấy giờ, này vương tử, người bện tóc thờ lửa ấy nghĩ rằng:",
  "dn23:21.7": "‘Hay là ta đi đến chỗ đoàn lữ hành ấy, biết đâu ở đó ta có thể kiếm được vật dụng gì đó.’",
  "dn23:21.8": "Rồi người bện tóc thờ lửa ấy dậy thật sớm, đi đến chỗ đoàn lữ hành ấy; đến nơi, ông thấy tại chỗ đoàn lữ hành có một bé trai còn nhỏ, yếu ớt, nằm ngửa, bị bỏ lại.",
  "dn23:21.9": "Thấy vậy, ông nghĩ rằng:",
  "dn23:21.10": "‘Thật không thích hợp cho ta nếu ngay trước mắt ta, một con người lại phải chết;",
  "dn23:21.11": "hay là ta đem đứa bé này về am, nuôi nấng, chăm sóc cho nó lớn lên.’",
  "dn23:21.12": "Rồi người bện tóc thờ lửa ấy đem đứa bé về am, nuôi nấng, chăm sóc cho nó lớn lên.",
  "dn23:21.13": "Khi đứa bé ấy được khoảng mười hai tuổi hoặc mười ba tuổi, thì người bện tóc thờ lửa ấy có việc cần phải đi đến một vùng quê.",
  "dn23:21.14": "Rồi người bện tóc thờ lửa ấy nói với đứa bé:",
  "dn23:21.15": "‘Con à, ta muốn đi đến vùng quê.",
  "dn23:21.16": "Con hãy chăm nom lửa.",
  "dn23:21.17": "Đừng để lửa tắt.",
  "dn23:21.18": "Nếu lửa có tắt, thì đây là rìu, đây là củi, đây là bộ cọ lửa; con hãy nhóm lửa lên rồi chăm nom lửa.’",
  "dn23:21.19": "Rồi người bện tóc thờ lửa ấy dạy bảo đứa bé như vậy xong thì đi đến vùng quê.",
  "dn23:21.20": "Trong khi mải mê vui chơi, lửa của nó bị tắt.",
  "dn23:21.21": "Rồi đứa bé ấy nghĩ rằng:",
  "dn23:21.22": "‘Cha đã dặn ta như vầy:",
  "dn23:21.23": "“Con à, hãy chăm nom lửa.",
  "dn23:21.24": "Đừng để lửa tắt.",
  "dn23:21.25": "Nếu lửa có tắt, thì đây là rìu, đây là củi, đây là bộ cọ lửa; con hãy nhóm lửa lên rồi chăm nom lửa.”",
  "dn23:21.26": "Hay là ta nhóm lửa lên rồi chăm nom lửa.’",
  "dn23:21.27": "Rồi đứa bé ấy dùng rìu đẽo bộ cọ lửa:",
  "dn23:21.28": "‘Biết đâu ta có thể lấy được lửa.’",
  "dn23:21.29": "Nhưng nó không lấy được lửa.",
  "dn23:21.30": "Nó chẻ bộ cọ lửa ra làm hai, làm ba, làm bốn, làm năm, làm mười, làm trăm mảnh, băm vụn từng mảnh, rồi sau khi băm vụn từng mảnh, nó giã trong cối, giã trong cối xong lại tung ra trước gió lớn:",
  "dn23:21.31": "‘Biết đâu ta có thể lấy được lửa.’",
  "dn23:21.32": "Nhưng nó vẫn không lấy được lửa.",
  "dn23:21.33": "Rồi người bện tóc thờ lửa ấy, sau khi giải quyết xong công việc ở vùng quê, trở về am của mình; trở về rồi, ông nói với đứa bé ấy:",
  "dn23:21.34": "‘Này con, lửa của con chắc không bị tắt chứ?’",
  "dn23:21.35": "‘Thưa cha, ở đây trong lúc con mải mê vui chơi, lửa đã tắt.",
  "dn23:21.36": "Rồi con nghĩ rằng:",
  "dn23:21.37": "“Cha đã dặn con như vầy: con à, hãy chăm nom lửa.",
  "dn23:21.38": "Đừng để lửa tắt.",
  "dn23:21.39": "Nếu lửa có tắt, thì đây là rìu, đây là củi, đây là bộ cọ lửa; con hãy nhóm lửa lên rồi chăm nom lửa.”",
  "dn23:21.40": "Hay là con nhóm lửa lên rồi chăm nom lửa.”",
  "dn23:21.41": "Rồi con, thưa cha, đã dùng rìu đẽo bộ cọ lửa:",
  "dn23:21.42": "“Biết đâu con có thể lấy được lửa.”",
  "dn23:21.43": "Nhưng con không lấy được lửa.",
  "dn23:21.44": "Con chẻ bộ cọ lửa ra làm hai, làm ba, làm bốn, làm năm, làm mười, làm trăm mảnh, băm vụn từng mảnh, rồi sau khi băm vụn từng mảnh, con giã trong cối, giã trong cối xong lại tung ra trước gió lớn:",
  "dn23:21.45": "“Biết đâu con có thể lấy được lửa.”",
  "dn23:21.46": "Nhưng con vẫn không lấy được lửa.’",
  "dn23:21.47": "Bấy giờ người bện tóc thờ lửa ấy nghĩ rằng:",
  "dn23:21.48": "‘Đứa bé này thật ngu si, không khéo léo; làm sao nó lại có thể tìm lửa một cách phi lý như vậy được?’",
  "dn23:21.49": "Trong khi nó đang nhìn, ông lấy bộ cọ lửa rồi nhóm lên ngọn lửa, và nói với cậu bé ấy:",
  "dn23:21.50": "‘Này con, lửa phải được nhóm lên như vậy.",
  "dn23:21.51": "Chứ không phải như con ngu si, chưa thành thạo, tìm lửa một cách phi lý.’",
  "dn23:21.52": "Cũng vậy, này vị vương tử, ông ngu si, chưa thành thạo, sẽ tìm kiếm đời sau một cách phi lý.",
  "dn23:21.53": "Hãy từ bỏ ác kiến này đi, này vị vương tử; hãy từ bỏ ác kiến này đi, này vị vương tử.",
  "dn23:21.54": "Chớ để điều ấy đem lại bất lợi và khổ đau cho ông trong thời gian dài.’",
  "dn23:22.1": "‘Dù Tôn giả Kassapa nói như vậy, nhưng tôi vẫn không thể từ bỏ ác kiến này.",
  "dn23:22.2": "Vua Pasenadi nước Kosala cũng biết tôi, các vua ngoài biên cũng biết tôi:",
  "dn23:22.3": "“Vương tử Pāyāsi là người có chủ trương như vậy, có kiến giải như vậy:",
  "dn23:22.4": "‘Không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp lành và dữ.’”",
  "dn23:22.5": "Nếu tôi, thưa Tôn giả Kassapa, từ bỏ ác kiến này, người ta sẽ nói về tôi rằng:",
  "dn23:22.6": "“Vương tử Pāyāsi thật ngu si, chưa thành thạo, chấp giữ điều sai lầm.”",
  "dn23:22.7": "Dù vì giận dữ tôi cũng sẽ giữ lấy nó, dù vì cố chấp tôi cũng sẽ giữ lấy nó, dù vì kiêu trá tôi cũng sẽ giữ lấy nó.’",
  "dn23:23.0": "2.11. Ví dụ hai người dẫn đoàn buôn",
  "dn23:23.1": "‘Vậy thì, này vị vương tử, tôi sẽ nêu cho ông một ví dụ.",
  "dn23:23.2": "Nhờ ví dụ, ở đây có những người trí hiểu được ý nghĩa lời nói.",
  "dn23:23.3": "Thuở xưa, này vị vương tử, có một đại thương đoàn gồm một ngàn cỗ xe đi từ xứ phương Đông đến xứ phương Tây.",
  "dn23:23.4": "Đoàn ấy đi đến đâu thì cỏ, củi, nước và lá xanh ở đó nhanh chóng bị dùng hết.",
  "dn23:23.5": "Trong đoàn ấy có hai người dẫn đoàn buôn, một người dẫn năm trăm cỗ xe, một người dẫn năm trăm cỗ xe.",
  "dn23:23.6": "Rồi hai người dẫn đoàn buôn ấy nghĩ rằng:",
  "dn23:23.7": "‘Đây là một đại thương đoàn gồm một ngàn cỗ xe;",
  "dn23:23.8": "nơi nào chúng ta đi qua thì cỏ, củi, nước và lá xanh ở đó nhanh chóng bị dùng hết.",
  "dn23:23.9": "Hay là chúng ta chia đoàn này làm hai—",
  "dn23:23.10": "một bên năm trăm cỗ xe, một bên năm trăm cỗ xe.’",
  "dn23:23.11": "Họ bèn chia đoàn ấy làm hai: một bên năm trăm cỗ xe, một bên năm trăm cỗ xe.",
  "dn23:23.12": "Một người dẫn đoàn buôn chất lên rất nhiều cỏ, củi và nước rồi cho đoàn lên đường.",
  "dn23:23.13": "Sau khi đi được hai ba ngày, đoàn ấy thấy một người đàn ông da đen, mắt đỏ, mang ống tên, đeo vòng hoa sen trắng, áo còn ướt, tóc còn ướt, đi trên một cỗ xe tốt với bánh xe dính đầy bùn, đang đi ngược chiều; thấy vậy, ông hỏi:",
  "dn23:23.14": "‘Này ông, ông từ đâu đến?’",
  "dn23:23.15": "‘Từ xứ tên là Amuka.’",
  "dn23:23.16": "‘Ông sẽ đi đâu?’",
  "dn23:23.17": "‘Đến xứ tên là Amuka.’",
  "dn23:23.18": "‘Này ông, phía trước trong khu rừng hoang có phải mưa lớn vừa đổ xuống không?’",
  "dn23:23.19": "‘Đúng vậy, này ông, phía trước trong khu rừng hoang mưa lớn vừa đổ xuống, các lối đi đầy nước, có nhiều cỏ, củi và nước.",
  "dn23:23.20": "Hãy bỏ bớt cỏ, củi và nước cũ đi, rồi cho xe nhẹ tải mà đi thật nhanh, thật nhanh, kẻo các con vật kéo xe bị mệt.’",
  "dn23:23.21": "Rồi người dẫn đoàn buôn ấy gọi những người trong đoàn lại:",
  "dn23:23.22": "‘Này các ông, người này nói như vầy:",
  "dn23:23.23": "“Phía trước trong khu rừng hoang mưa lớn vừa đổ xuống, các lối đi đầy nước, có nhiều cỏ, củi và nước.",
  "dn23:23.24": "Hãy bỏ cỏ, củi và nước cũ đi, rồi cho xe nhẹ tải mà đi thật nhanh, thật nhanh, kẻo các con vật kéo xe bị mệt.”",
  "dn23:23.25": "Này các ông, hãy bỏ cỏ, củi và nước cũ đi, rồi cho đoàn đi với những cỗ xe nhẹ tải.’",
  "dn23:23.26": "‘Vâng, thưa ông,’ những người trong đoàn đáp lời người dẫn đoàn buôn ấy, rồi bỏ cỏ, củi và nước cũ đi, cho đoàn đi với những cỗ xe nhẹ tải.",
  "dn23:23.27": "Nhưng ở chặng dừng chân thứ nhất, họ không thấy cỏ, cũng không thấy củi hay nước.",
  "dn23:23.28": "Ở chặng dừng chân thứ hai cũng vậy…",
  "dn23:23.29": "Ở chặng dừng chân thứ ba cũng vậy…",
  "dn23:23.30": "Ở chặng dừng chân thứ tư cũng vậy…",
  "dn23:23.31": "Ở chặng dừng chân thứ năm cũng vậy…",
  "dn23:23.32": "Ở chặng dừng chân thứ sáu cũng vậy…",
  "dn23:23.33": "Ở chặng dừng chân thứ bảy, họ cũng không thấy cỏ, cũng không thấy củi hay nước.",
  "dn23:23.34": "Tất cả đều rơi vào tai họa và diệt vong.",
  "dn23:23.35": "Những người và súc vật nào có trong đoàn ấy, tất cả đều bị con dạ-xoa phi nhân ấy ăn thịt.",
  "dn23:23.36": "Chỉ còn lại những bộ xương.",
  "dn23:23.37": "Khi người dẫn đoàn buôn thứ hai biết rằng: ",
  "dn23:23.38": "‘Này các vị, giờ đây đoàn buôn ấy đã đi xa rồi’, ông cho chất lên nhiều cỏ, củi và nước rồi cho đoàn buôn lên đường. ",
  "dn23:23.39": "Nhưng khi đoàn buôn ấy đi được hai ba ngày, ông thấy một người đàn ông da đen, mắt đỏ, mang ống tên, đeo vòng hoa sen trắng, y phục còn ướt, tóc còn ướt, đi ngược chiều trên cỗ xe tốt với bánh xe dính đầy bùn. Thấy vậy, ông hỏi người ấy: ",
  "dn23:23.40": "‘Này ông, ông từ đâu đến?’ ",
  "dn23:23.41": "‘Từ xứ nọ’, ",
  "dn23:23.42": "‘Ông sẽ đi đâu?’ ",
  "dn23:23.43": "‘Đến xứ tên là nọ.’ ",
  "dn23:23.44": "‘Này ông, có phải ở phía trước trong khu rừng hoang đã có mưa lớn đổ xuống chăng?’ ",
  "dn23:23.45": "‘Đúng vậy, này ông, ở phía trước trong khu rừng hoang đã có mưa lớn đổ xuống. Đường sá đầy nước, có nhiều cỏ, củi và nước. ",
  "dn23:23.46": "Này các vị, hãy bỏ cỏ cũ, củi cũ và nước cũ đi; hãy đi nhanh nhanh với những cỗ xe nhẹ bớt hàng, đừng để súc vật kéo xe bị mệt.’ ",
  "dn23:23.47": "Rồi người dẫn đoàn buôn ấy gọi những người trong đoàn lại: ",
  "dn23:23.48": "‘Này các vị, người này nói như vầy: ",
  "dn23:23.49": "“Ở phía trước trong khu rừng hoang đã có mưa lớn đổ xuống, đường sá đầy nước, có nhiều cỏ, củi và nước. ",
  "dn23:23.50": "Này các vị, hãy bỏ cỏ cũ, củi cũ và nước cũ đi; hãy đi nhanh nhanh với những cỗ xe nhẹ bớt hàng; đừng để súc vật kéo xe bị mệt.” ",
  "dn23:23.51": "Này các vị, người này chẳng phải bạn của chúng ta, cũng chẳng phải bà con huyết thống; làm sao chúng ta lại đi theo lòng tin nơi người này được? ",
  "dn23:23.52": "Các vị không được bỏ cỏ cũ, củi cũ và nước cũ; hãy cho đoàn buôn đi tiếp với hàng hóa được chở như cũ. ",
  "dn23:23.53": "Chúng ta sẽ không bỏ đồ cũ đâu.’ ",
  "dn23:23.54": "‘Vâng, thưa ông’, những người trong đoàn đáp lời người dẫn đoàn buôn ấy, rồi cho đoàn buôn đi tiếp với hàng hóa được chở như cũ. ",
  "dn23:23.55": "Nhưng ở chặng dừng thứ nhất, họ không thấy cỏ, củi hay nước nào cả. ",
  "dn23:23.56": "Ở chặng dừng thứ hai cũng vậy… ",
  "dn23:23.57": "Ở chặng dừng thứ ba cũng vậy… ",
  "dn23:23.58": "Ở chặng dừng thứ tư cũng vậy… ",
  "dn23:23.59": "Ở chặng dừng thứ năm cũng vậy… ",
  "dn23:23.60": "Ở chặng dừng thứ sáu cũng vậy… ",
  "dn23:23.61": "Ở chặng dừng thứ bảy cũng không thấy cỏ, củi hay nước nào cả. ",
  "dn23:23.62": "Rồi họ thấy đoàn buôn kia đã gặp tai họa, lạc đường và bị diệt vong. ",
  "dn23:23.63": "Những người hay súc vật nào có trong đoàn ấy, họ chỉ thấy xương cốt của chúng, vì đã bị con dạ-xoa phi nhân kia ăn thịt. ",
  "dn23:23.64": "Bấy giờ người dẫn đoàn buôn ấy gọi những người trong đoàn lại: ",
  "dn23:23.65": "‘Này các vị, đoàn buôn kia đã gặp tai họa, lạc đường và bị diệt vong, đúng như khi được dẫn dắt bởi người dẫn đoàn ngu si ấy. ",
  "dn23:23.66": "Vậy thì, này các vị, những món hàng ít giá trị trong đoàn của chúng ta, hãy bỏ chúng đi; còn những món hàng có giá trị lớn trong đoàn kia, hãy lấy chúng.’ ",
  "dn23:23.67": "‘Vâng, thưa ông’, những người trong đoàn đáp lời người dẫn đoàn buôn ấy. Họ bỏ những món hàng ít giá trị trong đoàn của mình, lấy những món hàng có giá trị lớn trong đoàn kia, rồi bình an vượt qua khu rừng hoang ấy, đúng như khi được người dẫn đoàn khôn ngoan dẫn dắt. ",
  "dn23:23.68": "Cũng vậy, này vương tử, ông là kẻ ngu si, thiếu sáng suốt, sẽ rơi vào tai họa, lạc đường và diệt vong khi tìm kiếm đời sau một cách phi lý, giống như người dẫn đoàn buôn thứ nhất kia. ",
  "dn23:23.69": "Những ai cho rằng điều của ông đáng nghe, đáng tin, họ cũng sẽ rơi vào tai họa, lạc đường và diệt vong, giống như những người trong đoàn kia. ",
  "dn23:23.70": "Này vương tử, hãy từ bỏ ác kiến này; này vương tử, hãy từ bỏ ác kiến này. ",
  "dn23:23.71": "Chớ để nó đem lại bất lợi và khổ đau cho ông trong thời gian dài.’ ",
  "dn23:24.1": "‘Dù tôn giả Kassapa nói như vậy, nhưng tôi vẫn không thể từ bỏ ác kiến này. ",
  "dn23:24.2": "Vua Pasenadi nước Kosala cũng biết tôi, các vua ở ngoài biên cương cũng biết tôi rằng: “Vương tử Pāyāsi có chủ trương như vậy, có kiến giải như vậy: ",
  "dn23:24.3": "‘Không có đời sau … không có quả báo.’” ",
  "dn23:24.4": "Nếu tôi từ bỏ ác kiến này, thưa Kassapa, người ta sẽ nói về tôi rằng: ",
  "dn23:24.5": "“Vương tử Pāyāsi thật ngu si, thiếu sáng suốt, chấp giữ điều sai lầm.” ",
  "dn23:24.6": "Dù vì giận dữ tôi cũng sẽ giữ lấy nó, dù vì cố chấp tôi cũng sẽ giữ lấy nó, dù vì hư danh tôi cũng sẽ giữ lấy nó.’ ",
  "dn23:25.0": "2.12. Ví dụ người gánh phân ",
  "dn23:25.1": "‘Vậy thì, này vương tử, tôi sẽ nêu cho ông một ví dụ. ",
  "dn23:25.2": "Nhờ ví dụ mà ở đây có những người trí hiểu được ý nghĩa lời nói. ",
  "dn23:25.3": "Thuở xưa, này vương tử, có một người nuôi heo từ làng mình đi đến một làng khác. ",
  "dn23:25.4": "Tại đó, ông thấy có nhiều phân khô bị vứt bỏ. ",
  "dn23:25.5": "Thấy vậy, ông nghĩ rằng: ",
  "dn23:25.6": "“Đây có nhiều phân khô bị vứt bỏ, mà lại là thức ăn cho heo của ta; ",
  "dn23:25.7": "hay là ta mang phân khô này đi từ đây.” ",
  "dn23:25.8": "Rồi ông trải áo ngoài ra, xúc nhiều phân khô đổ vào, buộc thành bọc, đội lên đầu rồi đi.",
  "dn23:25.9": "Trên đường đi, một đám mây trái mùa lớn đổ mưa xuống.",
  "dn23:25.10": "Người ấy, phân trào ra chảy xuống, từ đầu đến tận móng chân đều bị bôi đầy phân, mang một gánh phân mà đi.",
  "dn23:25.11": "Thấy người ấy, mọi người nói như sau:",
  "dn23:25.12": "‘Này anh, anh có điên không, anh có mất trí không? Sao lại mang một gánh phân, trong khi phân trào ra chảy xuống, từ đầu đến tận móng chân đều bị bôi đầy phân như thế?’",
  "dn23:25.13": "‘Chính các anh mới là điên, chính các anh mới là mất trí; vì đối với tôi, đây là cơm heo.’",
  "dn23:25.14": "Cũng vậy, này vương tử, ta nghĩ ông hiện ra giống như kẻ mang gánh phân.",
  "dn23:25.15": "Hãy từ bỏ tà kiến xấu ác này đi, này vương tử; hãy từ bỏ tà kiến xấu ác này đi, này vương tử.",
  "dn23:25.16": "Chớ để nó đem lại bất lợi và khổ đau cho ông trong thời gian dài.’",
  "dn23:26.1": "‘Dù tôn giả Kassapa nói như vậy, nhưng tôi vẫn không thể từ bỏ tà kiến xấu ác này.",
  "dn23:26.2": "Vua Pasenadi nước Kosala cũng biết tôi, các vị vua ở ngoài biên cũng biết:",
  "dn23:26.3": "“Vương tử Pāyāsi là người nói như vầy, có kiến chấp như vầy:",
  "dn23:26.4": "‘Không có đời sau … không có quả báo.’”",
  "dn23:26.5": "Nếu tôi từ bỏ tà kiến xấu ác này, thưa tôn giả Kassapa, người ta sẽ nói về tôi rằng:",
  "dn23:26.6": "“Vương tử Pāyāsi thật ngu si, không khéo léo, chấp giữ sai lầm.”",
  "dn23:26.7": "Dù vì giận dữ, dù vì ngoan cố, dù vì hư ngụy, tôi cũng sẽ giữ lấy nó.’",
  "dn23:27.0": "2.13. Ví dụ kẻ cờ bạc",
  "dn23:27.1": "‘Vậy thì, này vương tử, ta sẽ nêu cho ông một ví dụ,",
  "dn23:27.2": "vì nhờ ví dụ mà ở đây có những người trí hiểu được ý nghĩa lời nói.",
  "dn23:27.3": "Thuở xưa, này vương tử, có hai kẻ cờ bạc chơi xúc xắc với nhau.",
  "dn23:27.4": "Một kẻ cờ bạc nuốt luôn con xúc xắc thắng vừa xuất hiện.",
  "dn23:27.5": "Kẻ cờ bạc thứ hai thấy kẻ ấy cứ nuốt con xúc xắc thắng vừa xuất hiện, thấy vậy liền nói với kẻ ấy:",
  "dn23:27.6": "‘Này bạn, bạn thắng chắc rồi đấy; đưa xúc xắc cho tôi, này bạn, tôi sẽ làm sạch chúng.’",
  "dn23:27.7": "‘Được thôi, bạn,’ kẻ cờ bạc ấy đáp, rồi đưa xúc xắc cho người kia.",
  "dn23:27.8": "Rồi kẻ cờ bạc kia tẩm thuốc độc vào xúc xắc và nói với người ấy:",
  "dn23:27.9": "‘Nào, này bạn, chúng ta hãy chơi xúc xắc đi.’",
  "dn23:27.10": "‘Được thôi, bạn,’ kẻ cờ bạc ấy đáp lại người kia.",
  "dn23:27.11": "Rồi hai kẻ cờ bạc ấy lại chơi xúc xắc lần thứ hai.",
  "dn23:27.12": "Lần thứ hai nữa, kẻ cờ bạc ấy lại nuốt con xúc xắc thắng vừa xuất hiện.",
  "dn23:27.13": "Kẻ cờ bạc thứ hai thấy kẻ ấy lần thứ hai cũng nuốt con xúc xắc thắng vừa xuất hiện, thấy vậy liền nói với kẻ ấy:",
  "dn23:27.14": "‘Đã được bôi bằng chất cực độc,",
  "dn23:27.15": "Người nuốt quân xúc xắc không hay biết;",
  "dn23:27.16": "Nuốt đi, nuốt đi, đồ cờ bạc xấu xa,",
  "dn23:27.17": "Về sau ngươi sẽ thấy đắng cay.’",
  "dn23:27.18": "Cũng vậy, này vương tử, ta nghĩ ông hiện ra giống như kẻ cờ bạc ấy.",
  "dn23:27.19": "Hãy từ bỏ tà kiến xấu ác này đi, này vương tử; hãy từ bỏ tà kiến xấu ác này đi, này vương tử.",
  "dn23:27.20": "Chớ để nó đem lại bất lợi và khổ đau cho ông trong thời gian dài.’",
  "dn23:28.1": "‘Dù tôn giả Kassapa nói như vậy, nhưng tôi vẫn không thể từ bỏ tà kiến xấu ác này.",
  "dn23:28.2": "Vua Pasenadi nước Kosala cũng biết tôi, các vị vua ở ngoài biên cũng biết:",
  "dn23:28.3": "“Vương tử Pāyāsi là người nói như vầy, có kiến chấp như vầy:",
  "dn23:28.4": "‘Không có đời sau … không có quả báo.’”",
  "dn23:28.5": "Nếu tôi từ bỏ tà kiến xấu ác này, thưa tôn giả Kassapa, người ta sẽ nói về tôi rằng:",
  "dn23:28.6": "“Vương tử Pāyāsi thật ngu si, không khéo léo, chấp giữ sai lầm.”",
  "dn23:28.7": "Dù vì giận dữ, dù vì ngoan cố, dù vì hư ngụy, tôi cũng sẽ giữ lấy nó.’",
  "dn23:29.0": "2.14. Ví dụ gánh sợi gai",
  "dn23:29.1": "‘Vậy thì, này vương tử, ta sẽ nêu cho ông một ví dụ,",
  "dn23:29.2": "vì nhờ ví dụ mà ở đây có những người trí hiểu được ý nghĩa lời nói.",
  "dn23:29.3": "Thuở xưa, này vương tử, có một vùng quê bị hoang phế.",
  "dn23:29.4": "Rồi một người bạn nói với người bạn kia:",
  "dn23:29.5": "‘Nào bạn, chúng ta hãy đến vùng ấy, biết đâu ở đó có thể tìm được chút tài sản gì chăng.’",
  "dn23:29.6": "‘Được thôi, bạn,’ người bạn kia đáp lại.",
  "dn23:29.7": "Rồi họ đi đến một vùng quê, đến một xóm làng nào đó. Tại đó, ta thấy có rất nhiều cây gai bị vứt bỏ. Thấy vậy, người bạn nói với người bạn kia:",
  "dn23:29.8": "‘Này bạn, đây có rất nhiều cây gai bị vứt bỏ. Vậy thì bạn hãy bó một gánh gai, tôi cũng sẽ bó một gánh gai, rồi cả hai ta mang gánh gai mà đi.’",
  "dn23:29.9": "‘Vâng, bạn,’ người bạn ấy đáp lời người bạn kia, rồi bó một gánh gai. Cả hai mang gánh gai ấy đi đến một xóm làng khác.",
  "dn23:29.10": "Tại đó, họ thấy có rất nhiều sợi gai bị vứt bỏ. Thấy vậy, người bạn nói với người bạn kia:",
  "dn23:29.11": "‘Này bạn, điều mà chúng ta mong muốn từ cây gai, thì đây có rất nhiều sợi gai bị vứt bỏ.",
  "dn23:29.12": "Vậy thì bạn hãy bỏ gánh gai đi, tôi cũng sẽ bỏ gánh gai, rồi cả hai ta mang gánh sợi gai mà đi.’",
  "dn23:29.13": "‘Này bạn, gánh gai này của tôi đã được mang từ xa đến và buộc rất chắc rồi, thế là đủ cho tôi, bạn cứ biết vậy.’",
  "dn23:29.14": "Rồi người bạn ấy bỏ gánh gai đi và lấy gánh sợi gai.",
  "dn23:29.15": "Họ đi đến một xóm làng khác.",
  "dn23:29.16": "Tại đó, họ thấy có rất nhiều vải gai bị vứt bỏ. Thấy vậy, người bạn nói với người bạn kia:",
  "dn23:29.17": "‘Này bạn, điều mà chúng ta mong muốn từ cây gai hay từ sợi gai, thì đây có rất nhiều vải gai bị vứt bỏ.",
  "dn23:29.18": "Vậy thì bạn hãy bỏ gánh gai đi, tôi cũng sẽ bỏ gánh sợi gai, rồi cả hai ta mang gánh vải gai mà đi.’",
  "dn23:29.19": "‘Này bạn, gánh gai này của tôi đã được mang từ xa đến và buộc rất chắc rồi, thế là đủ cho tôi, bạn cứ biết vậy.’",
  "dn23:29.20": "Rồi người bạn ấy bỏ gánh sợi gai đi và lấy gánh vải gai.",
  "dn23:29.21": "Họ đi đến một xóm làng khác.",
  "dn23:29.22": "Tại đó, họ thấy có rất nhiều vải lanh bị vứt bỏ. Thấy vậy…",
  "dn23:29.23": "có rất nhiều sợi lanh bị vứt bỏ. Thấy vậy…",
  "dn23:29.24": "có rất nhiều vải lanh dệt bị vứt bỏ. Thấy vậy…",
  "dn23:29.25": "có rất nhiều bông vải bị vứt bỏ. Thấy vậy…",
  "dn23:29.26": "có rất nhiều sợi bông bị vứt bỏ. Thấy vậy…",
  "dn23:29.27": "có rất nhiều vải bông bị vứt bỏ. Thấy vậy…",
  "dn23:29.28": "có rất nhiều sắt bị vứt bỏ. Thấy vậy…",
  "dn23:29.29": "có rất nhiều đồng bị vứt bỏ. Thấy vậy…",
  "dn23:29.30": "có rất nhiều thiếc bị vứt bỏ. Thấy vậy…",
  "dn23:29.31": "có rất nhiều chì bị vứt bỏ. Thấy vậy…",
  "dn23:29.32": "có rất nhiều bạc bị vứt bỏ. Thấy vậy…",
  "dn23:29.33": "có rất nhiều vàng bị vứt bỏ. Thấy vậy, người bạn nói với người bạn kia:",
  "dn23:29.34": "‘Này bạn, điều mà chúng ta mong muốn từ cây gai, hay sợi gai, hay vải gai, hay vải lanh, hay sợi lanh, hay vải lanh dệt, hay bông vải, hay sợi bông, hay vải bông, hay sắt, hay đồng, hay thiếc, hay chì, hay bạc, thì đây có rất nhiều vàng bị vứt bỏ.",
  "dn23:29.35": "Vậy thì bạn hãy bỏ gánh gai đi, tôi cũng sẽ bỏ gánh bạc, rồi cả hai ta mang gánh vàng mà đi.’",
  "dn23:29.36": "‘Này bạn, gánh gai này của tôi đã được mang từ xa đến và buộc rất chắc rồi, thế là đủ cho tôi, bạn cứ biết vậy.’",
  "dn23:29.37": "Rồi người bạn ấy bỏ gánh bạc đi và lấy gánh vàng.",
  "dn23:29.38": "Họ đi đến ngôi làng của mình.",
  "dn23:29.39": "Tại đó, người bạn nào mang gánh gai trở về thì cha mẹ không hoan nghênh, vợ con không hoan nghênh, bạn bè thân thuộc không hoan nghênh, và do nhân ấy người ấy cũng không đạt được an lạc, hoan hỷ.",
  "dn23:29.40": "Còn người bạn nào mang gánh vàng trở về thì cha mẹ cũng hoan nghênh, vợ con cũng hoan nghênh, bạn bè thân thuộc cũng hoan nghênh, và do nhân ấy người ấy đạt được an lạc, hoan hỷ.",
  "dn23:29.41": "Cũng vậy, này vị vương tử, ta nghĩ rằng ngài hiện ra giống như người mang gánh gai.",
  "dn23:29.42": "Hãy từ bỏ tà kiến xấu ác ấy đi, này vị vương tử; hãy từ bỏ tà kiến xấu ác ấy đi, này vị vương tử.",
  "dn23:29.43": "Chớ để điều ấy đem lại bất lợi và khổ đau cho ngài trong thời gian dài.’",
  "dn23:30.0": "3. Quy y",
  "dn23:30.1": "‘Ngay từ ví dụ trước, tôi đã hoan hỷ và thỏa mãn với tôn giả Kassapa rồi.",
  "dn23:30.2": "Nhưng tôi vẫn muốn được nghe những lời đáp khéo léo đối với các câu hỏi vi diệu này, nên tôi đã nghĩ phải làm trái ý tôn giả Kassapa.",
  "dn23:30.3": "Thật tuyệt vời, thưa tôn giả Kassapa, thật tuyệt vời, thưa tôn giả Kassapa.",
  "dn23:30.4": "Ví như, thưa tôn giả Kassapa, người ta dựng đứng lại vật bị úp xuống, mở ra vật bị che kín, chỉ đường cho kẻ lạc lối, hay cầm đèn vào trong bóng tối để những ai có mắt có thể thấy các sắc; cũng vậy, Chánh pháp đã được tôn giả Kassapa trình bày bằng nhiều cách.",
  "dn23:30.5": "Con nay xin quy y tôn giả Gotama, quy y Pháp, và quy y Tăng chúng Tỳ-kheo.",
  "dn23:30.6": "Xin tôn giả Kassapa ghi nhận con là cư sĩ, từ nay cho đến trọn đời đã quy y.",
  "dn23:30.7": "Và, thưa tôn giả Kassapa, tôi muốn cử hành một đại tế lễ. Xin tôn giả Kassapa chỉ dạy cho tôi điều gì sẽ đem lại lợi ích và an lạc lâu dài cho tôi.’",
  "dn23:31.0": "4. Luận về tế lễ",
  "dn23:31.1": "‘Này vị vương tử, trong loại tế lễ nào mà bò bị giết, dê cừu bị giết, gà heo bị giết, và các loài hữu tình khác bị tàn hại; và những người thọ nhận lại có tà kiến, tà tư duy, tà ngữ, tà nghiệp, tà mạng, tà tinh tấn, tà niệm, tà định, thì loại tế lễ như vậy không có quả lớn, không có lợi ích lớn, không có rực rỡ lớn, không có phô trương lớn.",
  "dn23:31.2": "Ví như, này vị vương tử, một người nông dân cầm hạt giống và cày đi vào rừng.",
  "dn23:31.3": "Tại đó, người ấy gieo hạt trên thửa ruộng xấu, nền đất xấu, chưa được dọn sạch gốc cây và gai góc; những hạt giống thì bể nát, hư thối, bị gió nắng làm hại, không có tinh chất, không được cất giữ tốt.",
  "dn23:31.4": "Lại nữa, mưa trời cũng không đổ xuống đúng thời, đều đặn.",
  "dn23:31.5": "Vậy những hạt giống ấy có tăng trưởng, nảy nở, phát triển sung mãn, và người nông dân có thu được quả lớn không?",
  "dn23:31.6": "Thưa Kassapa, không.",
  "dn23:31.7": "Cũng vậy, này vương tử, trong loại tế lễ nào mà bò bị giết, dê cừu bị giết, gà heo bị giết, các loài hữu tình khác bị tàn hại, và những người thọ nhận lại có tà kiến, tà tư duy, tà ngữ, tà nghiệp, tà mạng, tà tinh tấn, tà niệm, tà định, thì loại tế lễ ấy, này vương tử, không có quả lớn, không có lợi ích lớn, không có rực rỡ lớn, không có quảng đại lớn.",
  "dn23:31.8": "Còn trong loại tế lễ nào, này vương tử, không có bò bị giết, không có dê cừu bị giết, không có gà heo bị giết, không có các loài hữu tình khác bị tàn hại, và những người thọ nhận lại có chánh kiến, chánh tư duy, chánh ngữ, chánh nghiệp, chánh mạng, chánh tinh tấn, chánh niệm, chánh định, thì loại tế lễ ấy, này vương tử, có quả lớn, có lợi ích lớn, có rực rỡ lớn, có quảng đại lớn.",
  "dn23:31.9": "Ví như, này vương tử, một người nông dân cầm hạt giống và cày đi vào rừng.",
  "dn23:31.10": "Tại đó, trên thửa ruộng tốt, đất tốt, đã được dọn sạch gốc cây và gai góc, người ấy gieo những hạt giống còn nguyên vẹn, không hư thối, không bị gió nắng làm hại, chắc mẩy, được cất giữ tốt.",
  "dn23:31.11": "Và trời lại mưa đúng thời, tưới nhuần đầy đủ.",
  "dn23:31.12": "Vậy những hạt giống ấy có tăng trưởng, nảy nở, phát triển sung mãn, và người nông dân có thu được quả lớn không?",
  "dn23:31.13": "Thưa Kassapa, có.",
  "dn23:31.14": "Cũng vậy, này vương tử, trong loại tế lễ nào không có bò bị giết, không có dê cừu bị giết, không có gà heo bị giết, không có các loài hữu tình khác bị tàn hại, và những người thọ nhận lại có chánh kiến, chánh tư duy, chánh ngữ, chánh nghiệp, chánh mạng, chánh tinh tấn, chánh niệm, chánh định, thì loại tế lễ ấy, này vương tử, có quả lớn, có lợi ích lớn, có rực rỡ lớn, có quảng đại lớn.",
  "dn23:32.0": "5. Chuyện thanh niên Bà-la-môn Uttara",
  "dn23:32.1": "Bấy giờ, vương tử Pāyāsi cho thiết lập việc bố thí đến các sa-môn, bà-la-môn, người nghèo khổ, lữ khách và người xin ăn.",
  "dn23:32.2": "Nhưng trong cuộc bố thí ấy, thức ăn được cho là cháo cám với nước chua làm món phụ, và y phục thì là những tấm vải thô với chăn lông rẻ tiền.",
  "dn23:32.3": "Trong cuộc bố thí ấy, có một thanh niên Bà-la-môn tên là Uttara làm người phụ trách.",
  "dn23:32.4": "Sau khi bố thí, anh ta phát nguyện như sau:",
  "dn23:32.5": "“Do sự bố thí này, mong rằng tôi chỉ gặp lại vương tử Pāyāsi ở đời này, chớ không ở đời sau.”",
  "dn23:32.6": "Vương tử Pāyāsi nghe được rằng:",
  "dn23:32.7": "“Nghe nói thanh niên Bà-la-môn Uttara sau khi bố thí đã phát nguyện như sau:",
  "dn23:32.8": "‘Do sự bố thí này, mong rằng tôi chỉ gặp lại vương tử Pāyāsi ở đời này, chớ không ở đời sau.’”",
  "dn23:32.9": "Rồi vương tử Pāyāsi cho gọi thanh niên Bà-la-môn Uttara đến và nói với anh ta rằng:",
  "dn23:32.10": "“Có thật không, này con Uttara, sau khi bố thí con đã phát nguyện như sau:",
  "dn23:32.11": "‘Do sự bố thí này, mong rằng tôi chỉ gặp lại vương tử Pāyāsi ở đời này, chớ không ở đời sau’?”",
  "dn23:32.12": "“Thưa ngài, đúng vậy.”",
  "dn23:32.13": "“Nhưng vì sao, này con Uttara, sau khi bố thí con lại phát nguyện như sau:",
  "dn23:32.14": "‘Do sự bố thí này, mong rằng tôi chỉ gặp lại vương tử Pāyāsi ở đời này, chớ không ở đời sau’?",
  "dn23:32.15": "Chẳng phải chúng ta, này con Uttara, là những người mong cầu phước đức và trông đợi quả của bố thí sao?”",
  "dn23:32.16": "“Trong cuộc bố thí của ngài, thức ăn được cho là cháo cám với nước chua làm món phụ, thứ mà chính ngài còn không muốn dùng chân chạm đến, huống gì ăn; còn y phục thì là những tấm vải thô với chăn lông rẻ tiền, thứ mà chính ngài còn không muốn dùng chân chạm đến, huống gì mặc.",
  "dn23:32.17": "Nhưng ngài lại là người chúng tôi yêu mến, quý trọng; làm sao chúng tôi có thể gắn điều đáng yêu với điều không đáng yêu được?”",
  "dn23:32.18": "“Vậy thì, này con Uttara, loại thức ăn nào ta ăn, con hãy cho loại thức ăn ấy.",
  "dn23:32.19": "Và loại y phục nào ta mặc, con cũng hãy cho loại y phục ấy.”",
  "dn23:32.20": "“Vâng, thưa ngài,” thanh niên Bà-la-môn Uttara đáp lời vương tử Pāyāsi, rồi cho loại thức ăn đúng như vương tử Pāyāsi dùng.",
  "dn23:32.21": "Và cũng cho loại y phục đúng như vương tử Pāyāsi mặc.",
  "dn23:32.22": "Rồi vương tử Pāyāsi, do bố thí không cung kính, bố thí không tự tay, bố thí không chú tâm, bố thí như quăng bỏ, nên sau khi thân hoại mạng chung đã sinh vào cộng trú với chư thiên Tứ Đại Vương, trong cung trời Serīsaka trống vắng.",
  "dn23:32.23": "Còn người phụ trách cuộc bố thí ấy là thanh niên Bà-la-môn tên Uttara, do bố thí cung kính, bố thí tự tay, bố thí với sự chú tâm, bố thí không như quăng bỏ, nên sau khi thân hoại mạng chung đã sinh vào cõi lành, cõi trời, cộng trú với chư thiên Tam Thập Tam.",
  "dn23:33.0": "6. Thiên tử Pāyāsi",
  "dn23:33.1": "Bấy giờ, tôn giả Gavampati thường thường đi đến cung trời Serīsaka trống vắng để nghỉ ban ngày.",
  "dn23:33.2": "Rồi thiên tử Pāyāsi đi đến chỗ tôn giả Gavampati; đến nơi, đảnh lễ tôn giả Gavampati rồi đứng sang một bên. Khi thiên tử Pāyāsi đứng sang một bên, tôn giả Gavampati nói với vị ấy rằng:",
  "dn23:33.3": "“Này hiền hữu, ông là ai?”",
  "dn23:33.4": "“Bạch ngài, con là vương tử Pāyāsi.”",
  "dn23:33.5": "“Này hiền hữu, chẳng phải trước đây ông có tà kiến như sau sao:",
  "dn23:33.6": "‘Không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp thiện ác’?”",
  "dn23:33.7": "“Thật vậy, bạch ngài, trước đây con có tà kiến như sau:",
  "dn23:33.8": "‘Không có đời sau, không có chúng sinh hóa sinh, không có quả dị thục của các nghiệp thiện ác.’",
  "dn23:33.9": "Nhưng con đã được tôn giả Kumārakassapa làm cho từ bỏ ác kiến ấy.”",
  "dn23:33.10": "“Còn người phụ trách cuộc bố thí của ông là thanh niên Bà-la-môn tên Uttara, người ấy đã sinh về đâu?”",
  "dn23:33.11": "“Bạch ngài, người phụ trách cuộc bố thí của con là thanh niên Bà-la-môn tên Uttara, do bố thí cung kính, bố thí tự tay, bố thí với sự chú tâm, bố thí không như quăng bỏ, nên sau khi thân hoại mạng chung đã sinh vào cõi lành, cõi trời, cộng trú với chư thiên Tam Thập Tam.",
  "dn23:33.12": "Còn con, bạch ngài, do bố thí không cung kính, bố thí không tự tay, bố thí không chú tâm, bố thí như quăng bỏ, nên sau khi thân hoại mạng chung đã sinh vào cộng trú với chư thiên Tứ Đại Vương, trong cung trời Serīsaka trống vắng.",
  "dn23:33.13": "Vậy nên, bạch ngài Gavampati, xin hãy đi đến cõi người và báo rằng:",
  "dn23:33.14": "‘Hãy bố thí một cách cung kính, hãy bố thí bằng chính tay mình, hãy bố thí với sự chú tâm, hãy bố thí không như quăng bỏ.",
  "dn23:33.15": "Vương tử Pāyāsi do bố thí không cung kính, bố thí không tự tay, bố thí không chú tâm, bố thí như quăng bỏ, nên sau khi thân hoại mạng chung đã sinh vào cộng trú với chư thiên Tứ Đại Vương, trong cung trời Serīsaka trống vắng.’",
  "dn23:33.16": "Còn người thanh niên Bà-la-môn tên Uttara, là người lo liệu việc bố thí ấy, sau khi bố thí một cách cung kính, tự tay bố thí, bố thí với tâm tôn trọng, bố thí không vứt bỏ, thì sau khi thân hoại mạng chung, được sinh vào cõi lành, cõi trời, cộng trú với chư thiên cõi Tam Thập Tam.”",
  "dn23:34.1": "Bấy giờ Tôn giả Gavampati đi đến cõi người và tuyên bố như sau:",
  "dn23:34.2": "“Hãy bố thí một cách cung kính, hãy tự tay bố thí, hãy bố thí với tâm tôn trọng, hãy bố thí không vứt bỏ.",
  "dn23:34.3": "Vua Pāyāsi do bố thí không cung kính, không tự tay bố thí, không bố thí với tâm tôn trọng, bố thí như vứt bỏ, nên sau khi thân hoại mạng chung, được sinh cộng trú với chư thiên Tứ Đại Thiên Vương, trong cung trời Serīsaka trống không.",
  "dn23:34.4": "Còn người thanh niên Bà-la-môn tên Uttara, là người lo liệu việc bố thí ấy, sau khi bố thí một cách cung kính, tự tay bố thí, bố thí với tâm tôn trọng, bố thí không vứt bỏ, thì sau khi thân hoại mạng chung, được sinh vào cõi lành, cõi trời, cộng trú với chư thiên cõi Tam Thập Tam.”",
  "dn23:34.5": "Kinh Pāyāsi chấm dứt, thứ mười.",
  "dn23:34.6": "Đại Phẩm chấm dứt.",
  "dn23:35.0": "Tóm tắt:",
  "dn23:35.1": "Đại Bổn, Khởi Nguyên,",
  "dn23:35.2": "Niết-bàn và Thiện Kiến;",
  "dn23:35.3": "Janavasabha, Govinda,",
  "dn23:35.4": "Đại Hội, Những Câu Hỏi của Sakka;",
  "dn23:35.5": "Đại Niệm Xứ,",
  "dn23:35.6": "Pāyāsi là thứ mười.",
  "dn23:35.7": "Phần Pāḷi của Đại Phẩm đã chấm dứt."
}
window.BILARA["dn23"]["vi"]["dn23:source"] =
  "Dịch từ nguồn Pali https://suttacentral.net/";
